'use client';
import PageSkeleton from '@/components/ui/PageSkeleton';

import { useEffect, useState, useMemo } from 'react';
import { useUIStore } from '@/lib/store';
import { useTranslation } from '@/lib/i18n/translations';
import { FiCheck, FiX, FiClock, FiAlertCircle, FiUsers, FiBriefcase } from 'react-icons/fi';
import { groupApi, attendanceApi, teacherAttendanceApi, userApi, sessionApi } from '@/lib/api/client';
import toast from 'react-hot-toast';
import { UserRole } from '@/types';

type AttStatus = 'Present' | 'Absent' | 'Late' | 'Excused';
type TabType = 'students' | 'teachers';

// Fallback Mock Data for Demo
const fallbackGroups = [
    {
        id: 'g1', name: 'Groupe Al-Fatiha', students: [
            { id: 's1', firstName: 'Youssef', lastName: 'Zahra', fullName: 'Youssef Zahra' },
            { id: 's2', firstName: 'Amina', lastName: 'Zahra', fullName: 'Amina Zahra' },
            { id: 's3', firstName: 'Mohamed', lastName: 'Ali', fullName: 'Mohamed Ali' },
            { id: 's4', firstName: 'Ibrahim', lastName: 'Hassan', fullName: 'Ibrahim Hassan' },
            { id: 's5', firstName: 'Fatima', lastName: 'Oumar', fullName: 'Fatima Oumar' },
        ]
    },
    {
        id: 'g2', name: 'Groupe Al-Baqarah', students: [
            { id: 's6', firstName: 'Omar', lastName: 'Farooq', fullName: 'Omar Farooq' },
            { id: 's7', firstName: 'Aisha', lastName: 'Siddiq', fullName: 'Aisha Siddiq' },
            { id: 's8', firstName: 'Khadija', lastName: 'Tul Kubra', fullName: 'Khadija Tul Kubra' },
        ]
    }
];

const fallbackTeachers = [
    { id: 't1', firstName: 'Oustadh', lastName: 'Ahmad', fullName: 'Oustadh Ahmad', roles: [UserRole.Teacher] },
    { id: 't2', firstName: 'Cheikh', lastName: 'Mahmoud', fullName: 'Cheikh Mahmoud', roles: [UserRole.Teacher, UserRole.Admin] },
    { id: 't3', firstName: 'Moallima', lastName: 'Salma', fullName: 'Moallima Salma', roles: [UserRole.Teacher] },
];

const generateFallbackSessions = () => {
    const sessions = [];
    const today = new Date();
    const start = new Date(today);
    start.setDate(today.getDate() - 30);
    const end = new Date(today);
    end.setDate(today.getDate() + 30);

    const pseudoGuid = (i: number) => `00000000-0000-0000-0000-ffff${String(i).padStart(8, '0')}`;

    let idCounter = 1;
    for (let d = new Date(start); d <= end; d.setDate(d.getDate() + 1)) {
        const dayOfWeek = d.getDay();
        const dateStr = d.toISOString().split('T')[0];

        // Group 1 (g1): M/W/F
        if ([1, 3, 5].includes(dayOfWeek)) {
            sessions.push({
                id: pseudoGuid(idCounter++), groupId: 'g1', groupName: 'Groupe Al-Fatiha',
                teacherId: 't1', date: dateStr, startTime: '10:00', endTime: '12:00'
            });
        }
        // Group 2 (g2): T/Th
        if ([2, 4].includes(dayOfWeek)) {
            sessions.push({
                id: pseudoGuid(idCounter++), groupId: 'g2', groupName: 'Groupe Al-Baqarah',
                teacherId: 't2', date: dateStr, startTime: '14:00', endTime: '16:00'
            });
        }
    }
    return sessions;
};

export default function AttendancePage() {
    const { locale } = useUIStore();
    const { t } = useTranslation(locale);

    const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
    const [activeTab, setActiveTab] = useState<TabType>('students');
    const [loading, setLoading] = useState(false);

    // Data states
    const [allGroups, setAllGroups] = useState<any[]>([]);
    const [allTeachers, setAllTeachers] = useState<any[]>([]);
    const [allSessions, setAllSessions] = useState<any[]>([]);

    const [plannedSessions, setPlannedSessions] = useState<any[]>([]);
    const [selectedSession, setSelectedSession] = useState<string>('all');

    const [students, setStudents] = useState<any[]>([]);
    const [teachers, setTeachers] = useState<any[]>([]);

    // Attendance state: mapping Entity ID -> Status
    const [attendance, setAttendance] = useState<Record<string, AttStatus>>({});

    useEffect(() => {
        loadBaseData();
    }, []);

    useEffect(() => {
        loadAttendanceForDate();
    }, [date, activeTab, selectedSession]);

    const loadBaseData = async () => {
        try {
            const [groupRes, devRes, sessRes] = await Promise.all([
                groupApi.getAll(),
                userApi.getAll(),
                sessionApi.getAll()
            ]);
            setAllGroups(groupRes.data);
            setAllSessions(sessRes.data);

            const profs = devRes.data.filter((u: any) =>
                u.roles?.includes(UserRole.Teacher) ||
                u.roles?.includes(UserRole.Admin) ||
                u.roles?.includes(UserRole.SuperAdmin) ||
                u.isExaminer
            );
            setAllTeachers(profs.length > 0 ? profs : fallbackTeachers);
        } catch (error) {
            console.error("Error loading base data", error);
            toast.error("Mode Démonstration : Données factices (API indisponible)");
            setAllGroups(fallbackGroups);
            setAllTeachers(fallbackTeachers);
            setAllSessions(generateFallbackSessions());
        }
    };

    const loadAttendanceForDate = async () => {
        if (!date) return;
        setLoading(true);
        try {
            const attMap: Record<string, AttStatus> = {};

            // Filter sessions for this date
            const sessionsForDate = allSessions.filter(s => {
                const sDate = s.date ? (typeof s.date === 'string' ? s.date.split('T')[0] : new Date(s.date).toISOString().split('T')[0]) : '';
                return sDate === date;
            });
            setPlannedSessions(sessionsForDate);

            if (activeTab === 'students') {
                let sessionStudents: any[] = [];
                if (selectedSession === 'all') {
                    // Get all students from all sessions today
                    const groupIds = Array.from(new Set(sessionsForDate.map(s => s.groupId)));
                    sessionStudents = allGroups.filter(g => groupIds.includes(g.id)).flatMap(g => g.students || []);
                    // Deduplicate
                    sessionStudents = Array.from(new Map(sessionStudents.map(s => [s.id, s])).values());
                } else {
                    const sess = sessionsForDate.find(s => s.id === selectedSession);
                    if (sess) {
                        const targetGroup = allGroups.find(g => g.id === sess.groupId);
                        sessionStudents = targetGroup?.students || [];
                    }
                }
                setStudents(sessionStudents);
                sessionStudents.forEach((s: any) => attMap[s.id] = 'Present');

                const res = await attendanceApi.getByDate(date);
                res.data.forEach((a: any) => {
                    if (attMap[a.studentId.toLowerCase()] !== undefined || attMap[a.studentId] !== undefined) {
                        attMap[a.studentId] = a.status;
                        attMap[a.studentId.toLowerCase()] = a.status;
                    }
                });
            } else if (activeTab === 'teachers') {
                // Filter teachers to only those who have planned sessions today
                const teacherIds = Array.from(new Set(sessionsForDate.map(s => s.teacherId)));
                const activeProfs = allTeachers.filter(t => teacherIds.includes(t.id));
                setTeachers(activeProfs);

                activeProfs.forEach((t: any) => attMap[t.id] = 'Present');

                const res = await teacherAttendanceApi.getByDate(date);
                res.data.forEach((a: any) => {
                    if (attMap[a.teacherId.toLowerCase()] !== undefined || attMap[a.teacherId] !== undefined) {
                        attMap[a.teacherId] = a.status;
                        attMap[a.teacherId.toLowerCase()] = a.status;
                    }
                });
            }
            setAttendance(attMap);
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    const statusConfig = {
        Present: { icon: <FiCheck />, color: 'bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-400 border-green-300 dark:border-green-700', label: 'Présent' },
        Absent: { icon: <FiX />, color: 'bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-400 border-red-300 dark:border-red-700', label: 'Absent' },
        Late: { icon: <FiClock />, color: 'bg-amber-100 dark:bg-amber-900/30 text-amber-700 dark:text-amber-400 border-amber-300 dark:border-amber-700', label: 'En retard' },
        Excused: { icon: <FiAlertCircle />, color: 'bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-400 border-blue-300 dark:border-blue-700', label: 'Excusé' },
    };

    const toggleStatus = (id: string) => {
        const order: AttStatus[] = ['Present', 'Absent', 'Late', 'Excused'];
        const currentId = Object.keys(attendance).find(k => k.toLowerCase() === id.toLowerCase()) || id;
        const current = attendance[currentId] || 'Present';
        const next = order[(order.indexOf(current) + 1) % order.length];
        setAttendance({ ...attendance, [currentId]: next });
    };

    const handleSave = async () => {
        try {
            const dateObj = new Date(date).toISOString();

            if (activeTab === 'students') {
                const records = students.map(s => ({
                    studentId: s.id,
                    date: dateObj,
                    status: attendance[s.id] || attendance[s.id.toLowerCase()] || 'Present',
                    notes: ''
                }));
                await attendanceApi.bulkMark({ date: dateObj, records });
            } else {
                const records = teachers.map(t => ({
                    teacherId: t.id,
                    date: dateObj,
                    status: attendance[t.id] || attendance[t.id.toLowerCase()] || 'Present',
                    notes: ''
                }));
                await teacherAttendanceApi.bulkMark({ date: dateObj, records });
            }

            toast.success('Présences enregistrées avec succès!');
        } catch (error) {
            toast.error('Erreur de sauvegarde...');
        }
    };

    const activeList = activeTab === 'students' ? students : teachers;

    const stats = useMemo(() => {
        let present = 0, absent = 0, late = 0, excused = 0;
        activeList.forEach((person) => {
            const targetId = Object.keys(attendance).find(k => k.toLowerCase() === person.id.toLowerCase()) || person.id;
            const status = attendance[targetId] || 'Present';
            if (status === 'Present') present++;
            else if (status === 'Absent') absent++;
            else if (status === 'Late') late++;
            else if (status === 'Excused') excused++;
        });
        return { present, absent, late, excused };
    }, [attendance, activeList]);

    if (loading) return <PageSkeleton variant="table" />;

    return (
        <div className="space-y-6">
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                <div>
                    <h1 className="text-2xl font-bold">{t.common.attendance}</h1>
                    <p className="text-dark-400 mt-1">Marquage et reporting des présences</p>
                </div>
                <input type="date" value={date} onChange={e => setDate(e.target.value)} className="input-field w-full sm:w-auto" />
            </div>

            {/* Filter Tabs */}
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 bg-white dark:bg-dark-900 p-2 rounded-2xl border border-dark-100 dark:border-dark-800">
                <div className="flex gap-2 p-1 bg-dark-50 dark:bg-dark-800 rounded-xl w-full sm:w-auto overflow-x-auto">
                    <button
                        onClick={() => setActiveTab('students')}
                        className={`flex items-center gap-2 px-5 py-2.5 rounded-lg text-sm font-bold transition-all whitespace-nowrap ${activeTab === 'students' ? 'bg-white dark:bg-dark-900 text-primary-600 shadow-sm' : 'text-dark-400 hover:text-dark-700 dark:hover:text-dark-200'}`}
                    >
                        <FiUsers size={16} /> Élèves
                    </button>
                    <button
                        onClick={() => setActiveTab('teachers')}
                        className={`flex items-center gap-2 px-5 py-2.5 rounded-lg text-sm font-bold transition-all whitespace-nowrap ${activeTab === 'teachers' ? 'bg-white dark:bg-dark-900 text-blue-600 shadow-sm' : 'text-dark-400 hover:text-dark-700 dark:hover:text-dark-200'}`}
                    >
                        <FiBriefcase size={16} /> Enseignants
                    </button>
                </div>

                {activeTab === 'students' && (
                    <select
                        value={selectedSession}
                        onChange={e => setSelectedSession(e.target.value)}
                        className="input-field bg-dark-50 dark:bg-dark-800 border-none w-full sm:w-auto font-medium shadow-none"
                    >
                        <option value="all">Toutes les séances de la journée</option>
                        {plannedSessions.map(s => (
                            <option key={s.id} value={s.id}>Séance {s.groupName} ({s.startTime?.substring(0, 5)})</option>
                        ))}
                    </select>
                )}
            </div>

            {/* Stats */}
            <div className={`grid grid-cols-2 md:grid-cols-5 gap-4 animate-fade-in`}>
                <div className="glass-card p-4 text-center gradient-primary text-white border-none relative overflow-hidden">
                    <div className="absolute top-0 right-0 p-2 opacity-20">
                        <FiUsers size={60} className="-mt-4 -mr-4" />
                    </div>
                    <p className="text-3xl font-black relative z-10">
                        {activeList.length > 0 ? Math.round((stats.present / activeList.length) * 100) : 0}%
                    </p>
                    <p className="text-sm font-medium text-white/80 relative z-10 mt-1">Taux de présence</p>
                </div>
                <div className="glass-card p-4 text-center">
                    <p className="text-2xl font-bold text-green-500">{stats.present}</p>
                    <p className="text-sm font-medium text-dark-400">Présents</p>
                </div>
                <div className="glass-card p-4 text-center">
                    <p className="text-2xl font-bold text-red-500">{stats.absent}</p>
                    <p className="text-sm font-medium text-dark-400">Absents</p>
                </div>
                <div className="glass-card p-4 text-center">
                    <p className="text-2xl font-bold text-amber-500">{stats.late}</p>
                    <p className="text-sm font-medium text-dark-400">En retard</p>
                </div>
                <div className="glass-card p-4 text-center">
                    <p className="text-2xl font-bold text-blue-500">{stats.excused}</p>
                    <p className="text-sm font-medium text-dark-400">Excusés</p>
                </div>
            </div>

            {/* Attendance List */}
            <div className="glass-card divide-y divide-dark-100 dark:divide-dark-700 min-h-[300px]">
                {loading ? (
                    <div className="flex justify-center items-center h-48 text-dark-400">Chargement...</div>
                ) : activeList.length === 0 ? (
                    <div className="flex flex-col justify-center items-center h-48 text-dark-400 text-sm">
                        <FiAlertCircle size={32} className="mb-2 opacity-50" />
                        {activeTab === 'students' ? 'Aucun élève prévu pour cette date/séance.' : 'Aucun enseignant assigné à une séance aujourd\'hui.'}
                    </div>
                ) : (
                    activeList.map((person) => {
                        const targetId = Object.keys(attendance).find(k => k.toLowerCase() === person.id.toLowerCase()) || person.id;
                        const status = attendance[targetId] || 'Present';
                        const config = statusConfig[status];
                        const name = person.fullName || person.name || `${person.firstName || ''} ${person.lastName || ''}`.trim();

                        return (
                            <div key={person.id} className="flex flex-col sm:flex-row sm:items-center justify-between p-4 hover:bg-dark-50 dark:hover:bg-dark-800/50 transition-colors gap-4">
                                <div className="flex items-center gap-3">
                                    <div className={`w-10 h-10 rounded-full flex items-center justify-center text-white font-bold text-sm shadow-sm ${activeTab === 'students' ? 'gradient-primary' : 'bg-gradient-to-br from-blue-500 to-blue-600'}`}>
                                        {name.charAt(0).toUpperCase()}
                                    </div>
                                    <div>
                                        <div className="flex items-center gap-2">
                                            <p className="font-bold text-dark-900 dark:text-white">{name}</p>
                                            {status === 'Absent' && (
                                                <span className="px-1.5 py-0.5 rounded text-[10px] font-bold bg-red-100 text-red-600 dark:bg-red-900/30 dark:text-red-400 uppercase">Alerte</span>
                                            )}
                                        </div>
                                        <p className="text-xs font-medium text-dark-400 uppercase tracking-wider mt-0.5">
                                            {activeTab === 'students' ? 'Élève' : (person.roles?.[0] || 'Enseignant')}
                                        </p>
                                    </div>
                                </div>
                                <button
                                    onClick={() => toggleStatus(person.id)}
                                    className={`flex items-center justify-center gap-2 px-4 py-2 rounded-xl border text-sm font-bold shadow-sm transition-all duration-200 active:scale-95 ${config.color}`}
                                >
                                    {config.icon}
                                    {config.label}
                                </button>
                            </div>
                        );
                    })
                )}
            </div>

            {activeList.length > 0 && !loading && (
                <div className="flex justify-end sticky bottom-6 z-10">
                    <button onClick={handleSave} className="btn-primary flex items-center gap-2 shadow-xl shadow-primary-500/20">
                        <FiCheck size={18} /> {t.common.save} les présences
                    </button>
                </div>
            )}
        </div>
    );
}

'use client';
import PageSkeleton from '@/components/ui/PageSkeleton';

import { useEffect, useState, useRef, useMemo } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { useUIStore } from '@/lib/store';
import { useTranslation } from '@/lib/i18n/translations';
import { groupApi, studentApi, sessionApi } from '@/lib/api/client';
import { GroupResponse, StudentResponse, SessionResponse } from '@/types';
import {
    FiArrowLeft, FiEdit2, FiTrash2, FiUsers, FiClock, FiTarget,
    FiBookOpen, FiPlus, FiChevronRight, FiSearch, FiMoreVertical,
    FiCalendar, FiUserPlus, FiX
} from 'react-icons/fi';
import Link from 'next/link';
import toast from 'react-hot-toast';
import { missionsService } from '@/lib/services/missions';
import { MissionTargetType } from '@/types';

// ═══════════════════════════════════════════════════════════════════════════════
// MOCK DATA
// ═══════════════════════════════════════════════════════════════════════════════
function getMockGroup(id: string): GroupResponse {
    return {
        id, name: 'Groupe Al-Fatiha', level: 'Niveau 1', levelId: 'lv1',
        levelName: 'Niveau 1 — Sourates Courtes', levelOrder: 1,
        maxCapacity: 20, isActive: true, teacherName: 'Khalil Bennani', teacherId: 'u1',
        studentCount: 18, createdAt: '2024-09-01'
    };
}

const MOCK_STUDENTS: StudentResponse[] = [
    { id: 's1', firstName: 'Ahmed', lastName: 'Al-Farsi', fullName: 'Ahmed Al-Farsi', email: 'ahmed@example.com', enrollmentDate: '2024-09-01', avgScore: 88, attendanceRate: 95, lastSessionNote: 'Excellent', dateOfBirth: '2012-05-15', isActive: true, createdAt: '2024-09-01' },
    { id: 's2', firstName: 'Sara', lastName: 'Mansour', fullName: 'Sara Mansour', email: 'sara@example.com', enrollmentDate: '2024-09-05', avgScore: 92, attendanceRate: 98, lastSessionNote: 'Très studieuse', dateOfBirth: '2013-03-20', isActive: true, createdAt: '2024-09-05' },
    { id: 's3', firstName: 'Youssef', lastName: 'Benali', fullName: 'Youssef Benali', email: 'youssef@example.com', enrollmentDate: '2024-10-10', avgScore: 75, attendanceRate: 85, lastSessionNote: 'Un peu fatigué', dateOfBirth: '2011-11-12', isActive: true, createdAt: '2024-10-10' },
];

const MOCK_SESSIONS: SessionResponse[] = [
    { id: 'ses1', date: '2026-02-15T14:00', durationMinutes: 60, status: 'Completed', groupName: 'Groupe Al-Fatiha', startTime: '2026-02-15T14:00', endTime: '2026-02-15T15:00', groupId: 'g1', teacherId: 'u1', teacherName: 'Khalil Bennani', isOnline: false },
    { id: 'ses2', date: '2026-02-12T14:00', durationMinutes: 60, status: 'Completed', groupName: 'Groupe Al-Fatiha', startTime: '2026-02-12T14:00', endTime: '2026-02-12T15:00', groupId: 'g1', teacherId: 'u1', teacherName: 'Khalil Bennani', isOnline: false },
];

// ═══════════════════════════════════════════════════════════════════════════════
// PAGE
// ═══════════════════════════════════════════════════════════════════════════════
export default function GroupDetailsClient() {
    const { id } = useParams() as { id: string };
    const router = useRouter();
    const { locale } = useUIStore();
    const { t } = useTranslation(locale);

    const [group, setGroup] = useState<GroupResponse | null>(null);
    const [students, setStudents] = useState<StudentResponse[]>([]);
    const [sessions, setSessions] = useState<SessionResponse[]>([]);
    const [loading, setLoading] = useState(true);

    const [activeTab, setActiveTab] = useState<'students' | 'schedule' | 'history'>('students');
    const [searchTerm, setSearchTerm] = useState('');

    // Mission Modal State
    const [isMissionModalOpen, setIsMissionModalOpen] = useState(false);
    const [isSubmittingMission, setIsSubmittingMission] = useState(false);
    const [missionTargetType, setMissionTargetType] = useState<MissionTargetType>(MissionTargetType.Surah);
    const [missionTargetId, setMissionTargetId] = useState('');
    const [missionDesc, setMissionDesc] = useState('');
    const [missionDueDate, setMissionDueDate] = useState('');

    useEffect(() => {
        if (!id) return;
        loadData();
    }, [id]);

    const loadData = async () => {
        try {
            const [groupRes, studentsRes, sessionsRes] = await Promise.all([
                groupApi.getById(id),
                studentApi.getByGroup(id),
                sessionApi.getByGroup(id)
            ]);
            setGroup(groupRes.data);
            setStudents(studentsRes.data);
            setSessions(sessionsRes.data);
        } catch (e) {
            console.error('Failed to load group data', e);
            setGroup(getMockGroup(id));
            setStudents(MOCK_STUDENTS);
            setSessions(MOCK_SESSIONS);
        } finally { setLoading(false); }
    };

    const filteredStudents = useMemo(() => {
        return students.filter(s => s.fullName.toLowerCase().includes(searchTerm.toLowerCase()));
    }, [students, searchTerm]);

    const handleAssignMission = async () => {
        if (!missionTargetId && missionTargetType !== MissionTargetType.CustomText) {
            toast.error("Veuillez remplir la cible.");
            return;
        }
        if (!missionDueDate) {
            toast.error("Veuillez définir une date d'échéance.");
            return;
        }

        setIsSubmittingMission(true);
        try {
            await missionsService.createGroupMission(id, {
                studentId: '', // Unused param by group endpoint but required by generic DTO, backend ignores it
                targetType: missionTargetType,
                targetId: missionTargetType !== MissionTargetType.CustomText ? Number(missionTargetId) : undefined,
                customDescription: missionTargetType === MissionTargetType.CustomText ? missionDesc : missionDesc,
                dueDate: new Date(missionDueDate).toISOString(),
            });
            toast.success("Mission assignée à tout le groupe !");
            setIsMissionModalOpen(false);
            // Reset
            setMissionTargetId('');
            setMissionDesc('');
            setMissionDueDate('');
        } catch (error) {
            toast.error("Erreur lors de l'assignation de la mission.");
        } finally {
            setIsSubmittingMission(false);
        }
    };

    if (!group) return <div className="text-center py-12 text-dark-400">Groupe introuvable.</div>;

    if (loading) return <PageSkeleton variant="detail" />;

    return (
        <div className="space-y-5">
            {/* ══ Header Row ══ */}
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <Link href="/dashboard/groups" className="inline-flex items-center gap-1.5 text-sm font-medium text-dark-500 hover:text-primary-600 transition-colors">
                    <FiArrowLeft size={14} /> Retour à la liste
                </Link>
                <div className="flex items-center gap-2">
                    <button className="flex items-center gap-2 px-4 py-2 rounded-xl bg-white dark:bg-dark-900 border border-dark-200 dark:border-dark-800 text-sm font-bold text-dark-600 dark:text-dark-300 hover:bg-dark-50 transition-colors shadow-sm">
                        <FiEdit2 size={13} /> Modifier
                    </button>
                    <button onClick={() => toast.error('Action réservée aux administrateurs')} className="p-2.5 rounded-xl border border-dark-200 dark:border-dark-800 text-red-500 hover:bg-red-50 transition-colors">
                        <FiTrash2 size={14} />
                    </button>
                </div>
            </div>

            {/* ══ Hero Content ══ */}
            <div className="bg-white dark:bg-dark-900 rounded-3xl border border-dark-100 dark:border-dark-800 p-6 shadow-sm overflow-hidden relative">
                <div className="absolute top-0 right-0 w-64 h-64 bg-primary-100/30 dark:bg-primary-900/10 blur-3xl -mr-32 -mt-32 rounded-full" />

                <div className="flex flex-col md:flex-row gap-6 items-start relative z-10">
                    <div className="w-16 h-16 sm:w-20 sm:h-20 rounded-2xl gradient-primary flex items-center justify-center text-white text-3xl font-black shadow-lg shadow-primary-500/20">
                        {group.name.charAt(0)}
                    </div>
                    <div className="flex-1">
                        <div className="flex items-center gap-3 mb-1">
                            <h1 className="text-2xl font-bold text-dark-900 dark:text-white">{group.name}</h1>
                            <span className="text-[10px] font-bold px-2 py-0.5 rounded-full bg-green-100 text-green-700">Actif</span>
                        </div>
                        <div className="flex flex-wrap items-center gap-x-5 gap-y-2 text-sm">
                            <span className="flex items-center gap-1.5 text-dark-500"><FiUserPlus size={13} className="text-primary-600" /> {group.teacherName} (Enseignant)</span>
                            <span className="flex items-center gap-1.5 text-dark-500"><FiTarget size={13} className="text-purple-600" /> {group.levelName}</span>
                            <span className="flex items-center gap-1.5 text-dark-500"><FiUsers size={13} className="text-blue-600" /> {group.studentCount}/{group.maxCapacity} élèves</span>
                        </div>
                    </div>
                    <div className="flex flex-col gap-2 min-w-[200px]">
                        <button onClick={() => router.push(`/dashboard/sessions/new?groupId=${group.id}`)} className="btn btn-primary w-full py-2.5 rounded-xl text-sm font-bold flex items-center justify-center gap-2">
                            <FiPlus size={14} /> Démarrer une séance
                        </button>
                        <button
                            onClick={() => setIsMissionModalOpen(true)}
                            className="w-full py-2.5 rounded-xl bg-orange-500 hover:bg-orange-600 text-white text-sm font-bold hover:shadow-lg hover:-translate-y-0.5 transition-all flex items-center justify-center gap-2"
                        >
                            <FiTarget size={14} /> Assigner Mission
                        </button>
                    </div>
                </div>
            </div>

            {/* ══ Tabs Navigation ══ */}
            <div className="flex gap-2 p-1 bg-dark-100/50 dark:bg-dark-800/30 rounded-2xl w-fit">
                {[
                    { id: 'students', label: 'Élèves', icon: <FiUsers size={14} />, count: students.length },
                    { id: 'schedule', label: 'Horaires', icon: <FiClock size={14} /> },
                    { id: 'history', label: 'Historique', icon: <FiCalendar size={14} /> },
                ].map(tab => (
                    <button
                        key={tab.id}
                        onClick={() => setActiveTab(tab.id as any)}
                        className={`flex items-center gap-2 px-6 py-2 rounded-xl text-xs font-bold transition-all ${activeTab === tab.id ? 'bg-white dark:bg-dark-900 text-primary-600 shadow-sm' : 'text-dark-500 hover:text-dark-900 dark:hover:text-white'}`}
                    >
                        {tab.icon} {tab.label}
                        {tab.count !== undefined && <span className={`ml-1 px-1.5 py-0.5 rounded-md text-[9px] ${activeTab === tab.id ? 'bg-primary-100 text-primary-600' : 'bg-dark-200 text-dark-500'}`}>{tab.count}</span>}
                    </button>
                ))}
            </div>

            {/* ══ Tab Content ══ */}
            <div className="bg-white dark:bg-dark-900 rounded-3xl border border-dark-100 dark:border-dark-800 overflow-hidden shadow-sm min-h-[400px]">
                {activeTab === 'students' && (
                    <div className="flex flex-col h-full">
                        {/* Search & Bulk */}
                        <div className="p-4 border-b border-dark-50 dark:border-dark-800 flex flex-col md:flex-row justify-between items-center gap-3 bg-dark-50/30">
                            <div className="relative w-full md:w-80">
                                <FiSearch className="absolute left-3 top-1/2 -translate-y-1/2 text-dark-400" size={14} />
                                <input
                                    type="text"
                                    placeholder="Rechercher un élève..."
                                    value={searchTerm}
                                    onChange={e => setSearchTerm(e.target.value)}
                                    className="w-full pl-9 pr-4 py-2 bg-white dark:bg-dark-800 border border-dark-200 dark:border-dark-700 rounded-xl text-xs focus:ring-2 focus:ring-primary-500 outline-none transition-all" />
                            </div>
                            <div className="flex items-center gap-2">
                                <button className="text-xs font-bold text-primary-600 px-3 py-1.5 hover:bg-primary-50 dark:hover:bg-primary-900/10 rounded-lg transition-colors">Exporter liste</button>
                                <button className="flex items-center gap-1.5 px-4 py-2 rounded-xl gradient-primary text-white text-xs font-bold hover:opacity-90 transition-opacity">
                                    <FiUserPlus size={13} /> Ajouter un élève
                                </button>
                            </div>
                        </div>

                        {/* List */}
                        {filteredStudents.length === 0 ? (
                            <div className="flex-1 flex flex-col items-center justify-center p-12 text-center">
                                <FiSearch size={40} className="text-dark-200 mb-4" />
                                <p className="text-dark-500 font-medium">Aucun élève trouvé</p>
                                <p className="text-xs text-dark-400 mt-1">Réessayez avec un autre nom ou ajoutez-en un nouveau.</p>
                            </div>
                        ) : (
                            <div className="overflow-x-auto">
                                <table className="w-full text-left">
                                    <thead>
                                        <tr className="border-b border-dark-50 dark:border-dark-800 text-[10px] uppercase tracking-widest text-dark-400 font-bold">
                                            <th className="px-6 py-4">Élève</th>
                                            <th className="px-6 py-4">Assiduité</th>
                                            <th className="px-6 py-4">Note moyenne</th>
                                            <th className="px-6 py-4">Dernier retour</th>
                                            <th className="px-6 py-4 text-right">Action</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-dark-50 dark:divide-dark-800">
                                        {filteredStudents.map(student => (
                                            <tr key={student.id} className="group hover:bg-dark-50/50 dark:hover:bg-dark-800/30 transition-colors">
                                                <td className="px-6 py-4">
                                                    <div className="flex items-center gap-3">
                                                        <div className="w-9 h-9 rounded-full bg-dark-100 dark:bg-dark-800 flex items-center justify-center text-primary-600 font-bold text-xs">
                                                            {student.fullName.charAt(0)}
                                                        </div>
                                                        <div>
                                                            <Link href={`/dashboard/students/${student.id}`} className="text-sm font-bold text-dark-900 dark:text-white hover:text-primary-600 transition-colors">{student.fullName}</Link>
                                                            <p className="text-[10px] text-dark-400">{student.email}</p>
                                                        </div>
                                                    </div>
                                                </td>
                                                <td className="px-6 py-4">
                                                    <div className="flex items-center gap-2">
                                                        <div className="flex-1 w-12 h-1 bg-dark-100 dark:bg-dark-800 rounded-full overflow-hidden">
                                                            <div className="h-full bg-green-500 rounded-full" style={{ width: `${student.attendanceRate ?? 0}%` }} />
                                                        </div>
                                                        <span className="text-xs font-bold text-dark-700 dark:text-dark-300">{student.attendanceRate ?? 0}%</span>
                                                    </div>
                                                </td>
                                                <td className="px-6 py-4">
                                                    <span className={`text-xs font-bold px-2 py-0.5 rounded-lg ${(student.avgScore ?? 0) >= 80 ? 'bg-green-50 text-green-600' : 'bg-orange-50 text-orange-600'}`}>
                                                        {student.avgScore ?? 0}%
                                                    </span>
                                                </td>
                                                <td className="px-6 py-4 text-xs italic text-dark-400">{student.lastSessionNote}</td>
                                                <td className="px-6 py-4 text-right">
                                                    <button className="p-2 text-dark-400 hover:text-primary-600 hover:bg-primary-50 dark:hover:bg-primary-900/10 rounded-lg transition-all opacity-0 group-hover:opacity-100">
                                                        <FiMoreVertical size={14} />
                                                    </button>
                                                </td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        )}
                    </div>
                )}

                {activeTab === 'schedule' && (
                    <div className="p-8 text-center">
                        <div className="w-16 h-16 bg-dark-50 dark:bg-dark-800 rounded-2xl flex items-center justify-center mx-auto mb-4">
                            <FiClock size={24} className="text-dark-300" />
                        </div>
                        <h3 className="text-lg font-bold text-dark-900 dark:text-white">Planning du groupe</h3>
                        <p className="text-sm text-dark-400 mt-1 max-w-sm mx-auto">Consultez les créneaux hebdomadaires et la planification des séances à venir.</p>
                        <button className="btn btn-outline mt-6 rounded-xl text-xs font-bold px-6 border-dark-200">Gérer l'emploi du temps</button>
                    </div>
                )}

                {activeTab === 'history' && (
                    <div className="p-6">
                        <h3 className="text-sm font-bold text-dark-900 dark:text-white mb-4">Séances récentes</h3>
                        {sessions.length === 0 ? (
                            <div className="py-12 text-center text-dark-400 text-sm italic">Aucune séance enregistrée pour ce groupe.</div>
                        ) : (
                            <div className="space-y-3">
                                {sessions.map(session => (
                                    <div key={session.id} className="p-4 rounded-2xl border border-dark-100 dark:border-dark-800 flex items-center justify-between hover:bg-dark-50/50 transition-colors">
                                        <div className="flex items-center gap-3">
                                            <div className="w-10 h-10 rounded-xl bg-primary-50 dark:bg-primary-900/10 flex items-center justify-center text-primary-600">
                                                <FiCalendar size={18} />
                                            </div>
                                            <div>
                                                <p className="text-sm font-bold">{new Date(session.startTime).toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long' })}</p>
                                                <p className="text-[10px] text-dark-400">{new Date(session.startTime).toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' })} – {session.durationMinutes} min</p>
                                            </div>
                                        </div>
                                        <Link href={`/dashboard/sessions/${session.id}/report`} className="text-[10px] font-bold text-primary-600 hover:underline">Voir rapport</Link>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                )}
            </div>

            {/* ══ Modal Assigner Mission ══ */}
            {isMissionModalOpen && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-dark-900/50 backdrop-blur-sm p-4 animate-in fade-in duration-200">
                    <div className="bg-white dark:bg-dark-900 w-full max-w-md rounded-3xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200">
                        <div className="flex justify-between items-center p-6 border-b border-dark-100 dark:border-dark-800">
                            <h3 className="text-xl font-bold flex items-center gap-2">
                                <div className="w-8 h-8 rounded-full bg-orange-100 dark:bg-orange-900/30 text-orange-600 flex items-center justify-center">
                                    <FiTarget size={16} />
                                </div>
                                Mission de Groupe
                            </h3>
                            <button onClick={() => setIsMissionModalOpen(false)} className="text-dark-400 hover:text-dark-600 dark:hover:text-dark-200 p-2">
                                <FiX size={20} />
                            </button>
                        </div>

                        <div className="p-6 space-y-4">
                            <div>
                                <label className="block text-xs font-bold text-dark-700 dark:text-dark-300 mb-1.5">Type de Mission</label>
                                <select
                                    className="w-full bg-dark-50 dark:bg-dark-800 border border-dark-200 dark:border-dark-700 rounded-xl px-4 py-2.5 text-sm focus:ring-2 focus:ring-orange-500 outline-none"
                                    value={missionTargetType}
                                    onChange={(e) => setMissionTargetType(Number(e.target.value) as unknown as MissionTargetType)}
                                >
                                    <option value={MissionTargetType.Surah}>Sourate</option>
                                    <option value={MissionTargetType.Hizb}>Hizb</option>
                                    <option value={MissionTargetType.CustomText}>Texte / Tâche personnalisée</option>
                                </select>
                            </div>

                            {missionTargetType !== MissionTargetType.CustomText && (
                                <div>
                                    <label className="block text-xs font-bold text-dark-700 dark:text-dark-300 mb-1.5">Numéro ({missionTargetType === MissionTargetType.Surah ? 'Sourate' : 'Hizb'})</label>
                                    <input
                                        type="number"
                                        value={missionTargetId}
                                        onChange={e => setMissionTargetId(e.target.value)}
                                        className="w-full bg-dark-50 dark:bg-dark-800 border border-dark-200 dark:border-dark-700 rounded-xl px-4 py-2.5 text-sm focus:ring-2 focus:ring-orange-500 outline-none"
                                        placeholder="Ex: 1"
                                    />
                                </div>
                            )}

                            <div>
                                <label className="block text-xs font-bold text-dark-700 dark:text-dark-300 mb-1.5">Description (Optionnel)</label>
                                <textarea
                                    value={missionDesc}
                                    onChange={e => setMissionDesc(e.target.value)}
                                    className="w-full bg-dark-50 dark:bg-dark-800 border border-dark-200 dark:border-dark-700 rounded-xl px-4 py-2.5 text-sm focus:ring-2 focus:ring-orange-500 outline-none resize-none"
                                    rows={3}
                                    placeholder="Instructions spéciales pour les élèves..."
                                />
                            </div>

                            <div>
                                <label className="block text-xs font-bold text-dark-700 dark:text-dark-300 mb-1.5 ">Date d'échéance</label>
                                <input
                                    type="date"
                                    value={missionDueDate}
                                    onChange={e => setMissionDueDate(e.target.value)}
                                    className="w-full bg-dark-50 dark:bg-dark-800 border border-dark-200 dark:border-dark-700 rounded-xl px-4 py-2.5 text-sm focus:ring-2 focus:ring-orange-500 outline-none"
                                />
                            </div>
                        </div>

                        <div className="p-6 border-t border-dark-100 dark:border-dark-800 flex justify-end gap-3 bg-dark-50/50 dark:bg-dark-800/30">
                            <button
                                onClick={() => setIsMissionModalOpen(false)}
                                className="px-5 py-2.5 rounded-xl text-sm font-bold text-dark-600 hover:bg-dark-100 dark:hover:bg-dark-800 transition-colors"
                            >
                                Annuler
                            </button>
                            <button
                                onClick={handleAssignMission}
                                disabled={isSubmittingMission}
                                className="px-6 py-2.5 rounded-xl text-sm font-bold text-white bg-orange-500 hover:bg-orange-600 shadow-lg shadow-orange-500/20 hover:-translate-y-0.5 transition-all disabled:opacity-70 disabled:hover:translate-y-0 flex items-center justify-center min-w-[120px]"
                            >
                                {isSubmittingMission ? <span className="spinner w-4 h-4 border-white" /> : 'Assigner à tous'}
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

'use client';
import PageSkeleton from '@/components/ui/PageSkeleton';

import { useEffect, useState } from 'react';
import { useRouter, useParams } from 'next/navigation';
import { useAuthStore, useUIStore } from '@/lib/store';
import { format } from 'date-fns';
import { fr } from 'date-fns/locale';
import { FaArrowLeft, FaPaperPlane, FaCheck, FaTimes, FaGraduationCap, FaRegCommentDots } from 'react-icons/fa';
import Link from 'next/link';
import { homeworkApi } from '@/lib/api/client';
import { HomeworkResponse, HomeworkAssignmentResponse, UserRole } from '@/types';
import { useTranslation } from '@/lib/i18n/translations';

export default function HomeworkDetailsClient() {
    const { id } = useParams() as { id: string };
    const router = useRouter();
    const { user } = useAuthStore();
    const { locale } = useUIStore();
    const { t } = useTranslation(locale);
    const [loading, setLoading] = useState(true);
    const [homework, setHomework] = useState<HomeworkResponse | null>(null); // For Teacher
    const [assignment, setAssignment] = useState<HomeworkAssignmentResponse | null>(null); // For Student
    const [assignmentsList, setAssignmentsList] = useState<HomeworkAssignmentResponse[]>([]); // For Teacher (list of students)
    const [submissionNotes, setSubmissionNotes] = useState('');
    const [gradingData, setGradingData] = useState<{ [key: string]: { grade: number, feedback: string } }>({});

    useEffect(() => {
        if (!user || !id) return;
        fetchData();
    }, [user, id]);

    const fetchData = async () => {
        setLoading(true);
        try {
            const roles = (user?.roles || []) as unknown as string[];
            if (roles.includes(UserRole.Student) || roles.includes(UserRole.Parent)) {
                // Fetch Assignment
                const res = await homeworkApi.getAssignmentById(id);
                setAssignment(res.data);
            } else {
                // Fetch Homework + List of Assignments
                const hwRes = await homeworkApi.getById(id);
                setHomework(hwRes.data);

                const listRes = await homeworkApi.getAssignments(id);
                setAssignmentsList(listRes.data);
            }
        } catch (error) {
            console.error('Failed to fetch data', error);
        } finally {
            setLoading(false);
        }
    };

    const handleSubmitAssignment = async () => {
        try {
            await homeworkApi.submitAssignment(id, { notes: submissionNotes });
            // Add a clean toast here ideally, falling back to alert for now
            alert('Devoir soumis avec succès !');
            fetchData(); // Refresh
        } catch (error) {
            console.error('Failed to submit', error);
            alert('Échec de la soumission du devoir.');
        }
    };

    const handleGrade = async (assignmentId: string) => {
        const data = gradingData[assignmentId];
        if (!data) return;

        try {
            await homeworkApi.gradeAssignment(assignmentId, {
                grade: Number(data.grade),
                feedback: data.feedback
            });
            alert('Évaluation enregistrée avec succès !');
            fetchData(); // Refresh
        } catch (error) {
            console.error('Failed to grade', error);
        }
    };

    const handleGradingChange = (assignmentId: string, field: string, value: any) => {
        setGradingData(prev => ({
            ...prev,
            [assignmentId]: {
                ...prev[assignmentId],
                [field]: value
            }
        }));
    };

    if (loading) {
    if (loading) return <PageSkeleton variant="detail" />;

        return (
            <div className="flex justify-center items-center h-64">
                <div className="w-12 h-12 border-4 border-primary-100 border-t-primary-600 rounded-full animate-spin" />
            </div>
        );
    }

    // === STUDENT VIEW ===
    if (user?.roles?.includes(UserRole.Student) || user?.roles?.includes(UserRole.Parent)) {
        if (!assignment) return <div className="p-8 text-center text-dark-500 font-medium">Devoir introuvable.</div>;
        return (
            <div className="p-4 sm:p-6 max-w-4xl mx-auto space-y-6 animate-in fade-in zoom-in-95 duration-500">
                <Link
                    href="/dashboard/homework"
                    className="inline-flex items-center gap-2 px-4 py-2 bg-white dark:bg-dark-900 border border-dark-100 dark:border-dark-800 rounded-xl text-dark-500 hover:text-dark-900 dark:hover:text-white hover:shadow-md transition-all font-bold text-sm"
                >
                    <FaArrowLeft /> {/* Add translation later */} Retour aux devoirs
                </Link>

                <div className="bg-white dark:bg-dark-900 border border-dark-100 dark:border-dark-800 rounded-[2.5rem] p-8 sm:p-10 shadow-xl relative overflow-hidden">
                    <div className="absolute top-0 right-0 w-32 h-32 bg-primary-100 dark:bg-primary-900/30 rounded-bl-[6rem] -z-0 opacity-50" />

                    <div className="relative z-10 space-y-8">
                        <div className="flex flex-col md:flex-row md:items-start justify-between gap-4">
                            <div>
                                <h1 className="text-3xl font-extrabold text-dark-900 dark:text-white tracking-tight leading-tight mb-2">
                                    {assignment.homeworkTitle}
                                </h1>
                                <p className="text-sm font-bold uppercase tracking-widest text-dark-500 bg-dark-50 dark:bg-dark-800 inline-block px-3 py-1.5 rounded-lg">
                                    Échéance: {format(new Date(assignment.dueDate), 'PPP', { locale: locale === 'fr' ? fr : undefined })}
                                </p>
                            </div>
                            <span
                                className={`px-4 py-2 rounded-xl text-xs font-bold uppercase tracking-widest shadow-sm border ${assignment.status === 'Submitted' ? 'bg-emerald-50 text-emerald-700 border-emerald-200 dark:bg-emerald-900/40 dark:text-emerald-400 dark:border-emerald-800/50' :
                                    assignment.status === 'Graded' ? 'bg-blue-50 text-blue-700 border-blue-200 dark:bg-blue-900/40 dark:text-blue-400 dark:border-blue-800/50' :
                                        'bg-amber-50 text-amber-700 border-amber-200 dark:bg-amber-900/40 dark:text-amber-400 dark:border-amber-800/50'
                                    }`}
                            >
                                {assignment.status}
                            </span>
                        </div>

                        {assignment.teacherFeedback && (
                            <div className="bg-accent-50 dark:bg-accent-900/20 p-6 rounded-3xl border border-accent-100 dark:border-accent-800">
                                <h3 className="font-extrabold text-accent-700 dark:text-accent-300 flex items-center gap-2 mb-3">
                                    <FaRegCommentDots className="text-xl" /> Retour du professeur
                                </h3>
                                <p className="text-dark-700 dark:text-dark-300 font-medium leading-relaxed">{assignment.teacherFeedback}</p>
                                {assignment.grade !== null && (
                                    <div className="mt-4 inline-flex items-center gap-2 bg-white dark:bg-dark-800 px-4 py-2 rounded-xl shadow-sm border border-accent-100 dark:border-accent-800/50">
                                        <FaGraduationCap className="text-accent-500" />
                                        <span className="font-extrabold text-dark-900 dark:text-white">Note: {assignment.grade}/20</span>
                                    </div>
                                )}
                            </div>
                        )}

                        {(assignment.status === 'Pending' || assignment.status === 'Late') && user?.roles?.includes(UserRole.Student) ? (
                            <div className="border-t-2 border-dashed border-dark-100 dark:border-dark-800 pt-8 space-y-4">
                                <h3 className="font-extrabold text-xl text-dark-900 dark:text-white mb-2">Soumettre votre devoir</h3>
                                <textarea
                                    className="w-full bg-dark-50 dark:bg-dark-950 border-2 border-transparent focus:border-primary-500 rounded-2xl px-5 py-4 outline-none font-medium transition-all text-dark-900 dark:text-white resize-none"
                                    rows={5}
                                    placeholder="Écrivez vos notes, remarques ou collez un lien..."
                                    value={submissionNotes}
                                    onChange={(e) => setSubmissionNotes(e.target.value)}
                                />
                                <div className="flex justify-end pt-2">
                                    <button
                                        onClick={handleSubmitAssignment}
                                        className="bg-primary-600 hover:bg-primary-700 text-white font-extrabold py-3 px-8 rounded-2xl flex items-center justify-center gap-3 shadow-xl shadow-primary-500/30 hover:-translate-y-1 transition-all uppercase tracking-widest text-sm"
                                    >
                                        <FaPaperPlane /> Soumettre le devoir
                                    </button>
                                </div>
                            </div>
                        ) : (
                            <div className="border-t-2 border-dashed border-dark-100 dark:border-dark-800 pt-8">
                                <h3 className="font-extrabold text-xl text-dark-900 dark:text-white mb-4">Votre soumission</h3>
                                <div className="bg-dark-50 dark:bg-dark-950 p-6 rounded-2xl border border-dark-100 dark:border-dark-800">
                                    <p className="text-dark-700 dark:text-dark-300 font-medium whitespace-pre-wrap">
                                        {assignment.studentNotes || "Aucune note textuelle soumise."}
                                    </p>
                                </div>
                                <p className="text-xs font-bold uppercase tracking-widest text-dark-400 mt-4 flex items-center gap-2">
                                    <span className="w-2 h-2 rounded-full bg-emerald-500"></span>
                                    Soumis le: {assignment.submittedAt ? format(new Date(assignment.submittedAt), 'PPP p', { locale: locale === 'fr' ? fr : undefined }) : 'N/A'}
                                </p>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        );
    }

    // === TEACHER VIEW ===
    if (!homework) return <div className="p-8 text-center text-dark-500 font-medium">Devoir introuvable.</div>;
    return (
        <div className="p-4 sm:p-6 space-y-6 max-w-7xl mx-auto animate-in fade-in zoom-in-95 duration-500">
            <Link
                href="/dashboard/homework"
                className="inline-flex items-center gap-2 px-4 py-2 bg-white dark:bg-dark-900 border border-dark-100 dark:border-dark-800 rounded-xl text-dark-500 hover:text-dark-900 dark:hover:text-white hover:shadow-md transition-all font-bold text-sm"
            >
                <FaArrowLeft /> Retour aux devoirs
            </Link>

            <div className="bg-primary-900 dark:bg-primary-950 rounded-[2.5rem] p-8 sm:p-10 shadow-2xl relative overflow-hidden text-white border border-primary-800">
                <div className="absolute -right-20 -top-20 w-64 h-64 bg-accent-500/20 rounded-full blur-3xl mix-blend-screen" />
                <div className="absolute -left-20 -bottom-20 w-64 h-64 bg-primary-500/30 rounded-full blur-3xl mix-blend-screen" />

                <div className="relative z-10">
                    <h1 className="text-4xl font-extrabold tracking-tight mb-4">{homework.title}</h1>
                    <p className="text-primary-100 font-medium text-lg max-w-3xl leading-relaxed">{homework.description}</p>

                    <div className="flex flex-wrap gap-4 mt-8">
                        <div className="bg-white/10 backdrop-blur-md border border-white/20 px-5 py-2.5 rounded-xl">
                            <span className="block text-xs uppercase tracking-widest text-primary-200 font-bold mb-1">Échéance</span>
                            <span className="font-semibold">{format(new Date(homework.dueDate), 'PPP', { locale: locale === 'fr' ? fr : undefined })}</span>
                        </div>
                        {homework.groupName && (
                            <div className="bg-white/10 backdrop-blur-md border border-white/20 px-5 py-2.5 rounded-xl">
                                <span className="block text-xs uppercase tracking-widest text-primary-200 font-bold mb-1">Groupe</span>
                                <span className="font-semibold">{homework.groupName}</span>
                            </div>
                        )}
                        <div className="bg-white/10 backdrop-blur-md border border-white/20 px-5 py-2.5 rounded-xl">
                            <span className="block text-xs uppercase tracking-widest text-primary-200 font-bold mb-1">Type</span>
                            <span className="font-semibold">Type {homework.type}</span>
                        </div>
                    </div>
                </div>
            </div>

            <div className="bg-white dark:bg-dark-900 rounded-[2.5rem] shadow-xl border border-dark-100 dark:border-dark-800 overflow-hidden mt-8">
                <div className="p-8 border-b border-dark-100 dark:border-dark-800">
                    <h2 className="text-2xl font-extrabold text-dark-900 dark:text-white">Soumissions des élèves</h2>
                    <p className="text-dark-500 mt-1 font-medium">Évaluez et commentez les travaux rendus.</p>
                </div>

                <div className="overflow-x-auto">
                    <table className="w-full">
                        <thead className="bg-dark-50 dark:bg-dark-950/50">
                            <tr>
                                <th className="text-left p-6 text-xs font-bold uppercase tracking-widest text-dark-500">Élève</th>
                                <th className="text-left p-6 text-xs font-bold uppercase tracking-widest text-dark-500">Statut</th>
                                <th className="text-left p-6 text-xs font-bold uppercase tracking-widest text-dark-500">Soumis le</th>
                                <th className="text-left p-6 text-xs font-bold uppercase tracking-widest text-dark-500 w-1/4">Notes de l'élève</th>
                                <th className="text-left p-6 text-xs font-bold uppercase tracking-widest text-dark-500">Évaluation & Retour</th>
                                <th className="text-center p-6 text-xs font-bold uppercase tracking-widest text-dark-500">Action</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-dark-50 dark:divide-dark-800/50">
                            {assignmentsList.map((a: any) => (
                                <tr key={a.id} className="hover:bg-dark-50/50 dark:hover:bg-dark-800/30 transition-colors">
                                    <td className="p-6">
                                        <div className="flex items-center gap-3">
                                            <div className="w-10 h-10 rounded-xl bg-primary-100 dark:bg-primary-900/40 text-primary-700 dark:text-primary-300 flex items-center justify-center font-extrabold text-sm">
                                                {a.studentName?.charAt(0).toUpperCase() || '?'}
                                            </div>
                                            <span className="font-extrabold text-dark-900 dark:text-white">{a.studentName}</span>
                                        </div>
                                    </td>
                                    <td className="p-6">
                                        <span className={`px-3 py-1.5 rounded-xl text-xs font-bold uppercase tracking-widest inline-flex items-center shadow-sm ${a.status === 'Submitted' ? 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/40 dark:text-emerald-400' :
                                            a.status === 'Graded' ? 'bg-blue-100 text-blue-700 dark:bg-blue-900/40 dark:text-blue-400' :
                                                'bg-amber-100 text-amber-700 dark:bg-amber-900/40 dark:text-amber-400'
                                            }`}>
                                            {a.status}
                                        </span>
                                    </td>
                                    <td className="p-6 text-sm font-medium text-dark-500">
                                        {a.submittedAt ? format(new Date(a.submittedAt), 'MMM d, HH:mm') : '-'}
                                    </td>
                                    <td className="p-6 text-sm text-dark-600 dark:text-dark-400">
                                        <div className="max-w-[15rem] truncate font-medium bg-dark-50 dark:bg-dark-950 px-3 py-2 rounded-lg" title={a.studentNotes}>
                                            {a.studentNotes || <span className="text-dark-400 italic">Aucune note</span>}
                                        </div>
                                    </td>
                                    <td className="p-6">
                                        {a.status !== 'Pending' && (
                                            <div className="flex flex-col gap-3">
                                                <div className="flex items-center gap-2">
                                                    <span className="text-xs font-bold uppercase text-dark-400 w-12 text-right">Note</span>
                                                    <input
                                                        type="number"
                                                        placeholder="/20"
                                                        className="w-20 bg-dark-50 dark:bg-dark-950 border-2 border-transparent focus:border-primary-500 rounded-xl px-3 py-2 outline-none font-bold text-center transition-all text-dark-900 dark:text-white"
                                                        defaultValue={a.grade}
                                                        onChange={(e) => handleGradingChange(a.id, 'grade', e.target.value)}
                                                    />
                                                </div>
                                                <div className="flex items-start gap-2">
                                                    <span className="text-xs font-bold uppercase text-dark-400 w-12 text-right pt-2.5">Avis</span>
                                                    <input
                                                        type="text"
                                                        placeholder="Commentaire..."
                                                        className="w-48 bg-dark-50 dark:bg-dark-950 border-2 border-transparent focus:border-primary-500 rounded-xl px-3 py-2 outline-none font-medium transition-all text-dark-900 dark:text-white text-sm"
                                                        defaultValue={a.teacherFeedback}
                                                        onChange={(e) => handleGradingChange(a.id, 'feedback', e.target.value)}
                                                    />
                                                </div>
                                            </div>
                                        )}
                                    </td>
                                    <td className="p-6 text-center">
                                        {a.status === 'Submitted' || a.status === 'Graded' ? (
                                            <button
                                                onClick={() => handleGrade(a.id)}
                                                className="bg-accent-500 hover:bg-accent-600 text-white w-10 h-10 rounded-full flex items-center justify-center mx-auto shadow-md hover:scale-110 transition-transform disabled:opacity-50"
                                                title="Sauvegarder l'évaluation"
                                            >
                                                <FaCheck size={16} />
                                            </button>
                                        ) : (
                                            <span className="w-10 h-10 rounded-full bg-dark-50 dark:bg-dark-800 text-dark-300 dark:text-dark-600 flex items-center justify-center mx-auto">
                                                <FaTimes size={16} />
                                            </span>
                                        )}
                                    </td>
                                </tr>
                            ))}
                            {assignmentsList.length === 0 && (
                                <tr>
                                    <td colSpan={6} className="p-12 text-center text-dark-400 font-medium">
                                        Aucun élève n'est assigné à ce devoir.
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}

'use client';
import PageSkeleton from '@/components/ui/PageSkeleton';

import { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { useAuthStore, useUIStore } from '@/lib/store';
import { useTranslation } from '@/lib/i18n/translations';
import { homeworkApi, dashboardApi } from '@/lib/api/client';
import { UserRole } from '@/types';
import { format } from 'date-fns';
import { fr } from 'date-fns/locale';
import Link from 'next/link';
import { FaPlus, FaBookOpen, FaClock, FaCheckCircle, FaExclamationCircle } from 'react-icons/fa';

interface Homework {
    id: string;
    title: string;
    dueDate: string;
    groupName?: string;
    assignmentsCount?: number;
    submittedCount?: number;
    status?: string;
    grade?: number;
    studentName?: string;
    assignmentId?: string;
}

export default function HomeworkPage() {
    const router = useRouter();
    const { locale } = useUIStore();
    const { t } = useTranslation(locale);
    const { user } = useAuthStore();
    const [homeworks, setHomeworks] = useState<Homework[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        if (!user) return;
        fetchHomeworks();
    }, [user]);

    const fetchHomeworks = async () => {
        try {
            setLoading(true);
            let data;
            const roles = user?.roles || [];
            if (roles.includes(UserRole.Teacher) || roles.includes(UserRole.Admin) || roles.includes(UserRole.SuperAdmin)) {
                const res = await homeworkApi.getByTeacher();
                data = res.data;
            } else if (roles.includes(UserRole.Student)) {
                const res = await homeworkApi.getMyAssignments();
                data = res.data.map((a: any) => ({
                    id: a.homeworkId,
                    assignmentId: a.id,
                    title: a.homeworkTitle,
                    dueDate: a.dueDate,
                    status: a.status,
                    grade: a.grade,
                    teacherFeedback: a.teacherFeedback
                }));
            } else if (roles.includes(UserRole.Parent)) {
                const res = await dashboardApi.getParent(user!.userId);
                const childrenData = res.data.children || [];
                const allHomeworks: any[] = [];

                childrenData.forEach((child: any) => {
                    child.pendingHomeworks.forEach((hw: any) => {
                        allHomeworks.push({
                            ...hw,
                            studentName: child.fullName
                        });
                    });
                });
                data = allHomeworks;
            }
            setHomeworks(data || []);
        } catch (error) {
            console.error('Failed to fetch homeworks', error);
        } finally {
            setLoading(false);
        }
    };

    if (loading) {
        return (
            <div className="flex justify-center items-center h-64">
                <div className="w-12 h-12 border-4 border-primary-100 border-t-primary-600 rounded-full animate-spin" />
            </div>
        );
    }

    const isTeacher = user?.roles?.some(r => [UserRole.Teacher, UserRole.Admin, UserRole.SuperAdmin].includes(r));
    const isStudent = user?.roles?.includes(UserRole.Student);

    if (loading) return <PageSkeleton variant="table" />;

    return (
        <div className="space-y-8 animate-in fade-in zoom-in-95 duration-500 max-w-6xl mx-auto">
            <div className="flex flex-col sm:flex-row sm:items-end justify-between gap-4">
                <div>
                    <h1 className="text-4xl font-extrabold text-dark-900 dark:text-white tracking-tight">{t.homework.listTitle}</h1>
                    <p className="text-dark-500 mt-2 text-lg">Suivi des travaux et évaluations</p>
                </div>
                {isTeacher && (
                    <Link
                        href="/dashboard/homework/create"
                        className="bg-primary-600 hover:bg-primary-700 text-white font-bold py-3 px-6 rounded-2xl flex items-center justify-center gap-2 shadow-lg shadow-primary-500/30 hover:-translate-y-1 transition-all"
                    >
                        <FaPlus size={16} /> {t.homework.create}
                    </Link>
                )}
            </div>

            <div className="space-y-4">
                {homeworks.length === 0 ? (
                    <div className="bg-white dark:bg-dark-900 border border-dark-100 dark:border-dark-800 rounded-[2.5rem] p-16 text-center text-dark-500 shadow-xl flex flex-col items-center justify-center">
                        <div className="w-24 h-24 bg-dark-50 dark:bg-dark-800 rounded-full flex items-center justify-center mb-6 shadow-inner">
                            <FaBookOpen className="text-4xl text-dark-300 dark:text-dark-600" />
                        </div>
                        <p className="text-xl font-bold">{t.homework.noRecords}</p>
                        <p className="mt-2 text-dark-400 max-w-sm mx-auto">Aucun devoir n'est assigné pour le moment. Profitez de ce temps libre !</p>
                    </div>
                ) : (
                    <div className="grid grid-cols-1 gap-4">
                        {homeworks.map((hw) => (
                            <div
                                key={hw.id || hw.assignmentId}
                                className="bg-white dark:bg-dark-900 p-6 sm:p-8 rounded-[2rem] shadow-lg border border-dark-100 dark:border-dark-800 flex flex-col sm:flex-row sm:items-center justify-between gap-6 hover:shadow-xl transition-all group relative overflow-hidden"
                            >
                                {/* Aesthetic side accent */}
                                <div className="absolute left-0 top-0 bottom-0 w-2 bg-gradient-to-b from-primary-400 to-accent-500 opacity-80" />

                                <div className="pl-4">
                                    <h3 className="text-2xl font-extrabold text-dark-900 dark:text-white tracking-tight leading-tight group-hover:text-primary-600 dark:group-hover:text-primary-400 transition-colors">
                                        {hw.title}
                                    </h3>

                                    <div className="flex flex-wrap items-center gap-x-6 gap-y-3 mt-4 text-sm font-medium text-dark-600 dark:text-dark-400">
                                        <div className="flex items-center gap-2 bg-dark-50 dark:bg-dark-800 px-3 py-1.5 rounded-lg">
                                            <FaClock className="text-accent-500" />
                                            <span>{t.homework.due}: {format(new Date(hw.dueDate), 'PPP', { locale: locale === 'fr' ? fr : undefined })}</span>
                                        </div>

                                        {isTeacher && hw.groupName && (
                                            <div className="flex items-center gap-2">
                                                <span className="w-2 h-2 rounded-full bg-primary-500" />
                                                <span>{t.homework.group}: <strong className="text-dark-900 dark:text-white">{hw.groupName}</strong></span>
                                            </div>
                                        )}

                                        {user?.roles?.includes(UserRole.Parent) && hw.studentName && (
                                            <div className="flex items-center gap-2">
                                                <span className="w-2 h-2 rounded-full bg-blue-500" />
                                                <span>{t.homework.student}: <strong className="text-dark-900 dark:text-white">{hw.studentName}</strong></span>
                                            </div>
                                        )}
                                    </div>

                                    {isStudent && (
                                        <div className="mt-4 flex items-center gap-3">
                                            <span
                                                className={`text-xs font-bold uppercase tracking-widest px-3 py-1.5 rounded-xl flex items-center gap-1.5 shadow-sm ${hw.status === 'Submitted' ? 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/40 dark:text-emerald-400' :
                                                    hw.status === 'Graded' ? 'bg-blue-100 text-blue-700 dark:bg-blue-900/40 dark:text-blue-400' :
                                                        'bg-amber-100 text-amber-700 dark:bg-amber-900/40 dark:text-amber-400'
                                                    }`}
                                            >
                                                {hw.status === 'Submitted' || hw.status === 'Graded' ? <FaCheckCircle /> : <FaExclamationCircle />}
                                                {hw.status} {hw.grade !== null && `(${t.homework.grade}: ${hw.grade}/20)`}
                                            </span>
                                        </div>
                                    )}
                                </div>

                                <div className="flex justify-start sm:justify-end shrink-0 pl-4 sm:pl-0">
                                    <Link
                                        href={isTeacher ? `/dashboard/homework/${hw.id}` : `/dashboard/homework/${hw.assignmentId}`}
                                        className="bg-dark-50 hover:bg-dark-100 dark:bg-dark-800 dark:hover:bg-dark-700 text-dark-900 dark:text-white font-bold py-3 px-6 rounded-xl flex items-center gap-2 transition-colors border border-dark-200 dark:border-dark-700"
                                    >
                                        <FaBookOpen className="text-primary-500" /> {t.homework.view}
                                    </Link>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </div>
    );
}

'use client';

import { useAuthStore, useUIStore } from '@/lib/store';
import { useTranslation } from '@/lib/i18n/translations';
import { useRouter, usePathname } from 'next/navigation';
import Link from 'next/link';
import { useEffect, useState, ReactNode } from 'react';
import {
    FiHome, FiUsers, FiGrid, FiBook, FiCalendar, FiCheckSquare,
    FiMessageCircle, FiDollarSign, FiTrendingUp, FiMail, FiBell, FiSettings,
    FiLogOut, FiSun, FiMoon, FiMenu, FiGlobe, FiBookOpen, FiLayers, FiShield,
    FiChevronDown, FiChevronRight, FiX, FiTarget, FiAward, FiPieChart, FiMusic,
    FiMapPin
} from 'react-icons/fi';
import { usePermission, Permissions } from '@/hooks/usePermission';
import { UserRole } from '@/types';
import { notificationsService, NotificationResponse } from '@/lib/services/notifications';

type NavItem = { icon: ReactNode; label: string; href: string; permissions?: string[] };
type NavGroup = { title: string; items: NavItem[]; module?: string };

export default function DashboardLayout({ children }: { children: React.ReactNode }) {
    const { user, isAuthenticated, isLoading, logout } = useAuthStore();
    const { sidebarOpen, darkMode, locale, toggleSidebar, toggleDarkMode, setLocale } = useUIStore();
    const { t } = useTranslation(locale);
    const router = useRouter();
    const pathname = usePathname();

    // Section collapse state
    const [collapsedSections, setCollapsedSections] = useState<Record<string, boolean>>({});
    const [activeModule, setActiveModule] = useState<'scolarite' | 'gestion' | 'admin'>('scolarite');
    const [moduleMenuOpen, setModuleMenuOpen] = useState(false);
    const [settingsMenuOpen, setSettingsMenuOpen] = useState(false);

    // Notifications State
    const [notifications, setNotifications] = useState<NotificationResponse[]>([]);
    const [unreadCount, setUnreadCount] = useState(0);
    const [isNotificationsOpen, setIsNotificationsOpen] = useState(false);

    const sidebarModules = [
        { id: 'scolarite', label: 'École', icon: '🎓' },
        { id: 'gestion', label: 'Mosquée', icon: '🕌' },
        { id: 'admin', label: 'Administration', icon: '⚙️' },
    ];

    useEffect(() => {
        // Only redirect if loading is finished and not authenticated
        if (!isLoading && !isAuthenticated) {
            router.push('/login');
        }
    }, [isAuthenticated, isLoading, router]);

    useEffect(() => {
        if (isAuthenticated) {
            loadNotifications();
        }
    }, [isAuthenticated, pathname]);

    const loadNotifications = async () => {
        try {
            const data = await notificationsService.getMyNotifications();
            setNotifications(data);
            setUnreadCount(data.filter(n => !n.isRead).length);
        } catch (e) {
            console.error('Failed to load notifications', e);
        }
    };

    const handleMarkAsRead = async (id: string) => {
        try {
            await notificationsService.markAsRead(id);
            setNotifications(prev => prev.map(n => n.id === id ? { ...n, isRead: true } : n));
            setUnreadCount(prev => Math.max(0, prev - 1));
        } catch (e) {
            console.error(e);
        }
    };

    const handleMarkAllAsRead = async () => {
        try {
            await notificationsService.markAllAsRead();
            setNotifications(prev => prev.map(n => ({ ...n, isRead: true })));
            setUnreadCount(0);
        } catch (e) {
            console.error(e);
        }
    };

    // Close sidebar on navigation on mobile
    useEffect(() => {
        if (sidebarOpen && typeof window !== 'undefined' && window.innerWidth < 1024) {
            toggleSidebar();
        }
    }, [pathname]);

    const { hasAnyPermission } = usePermission();

    const navGroups: NavGroup[] = [
        {
            title: 'Général',
            items: [
                { icon: <FiHome size={18} />, label: t.common.dashboard, href: '/dashboard' },
                { icon: <FiUsers size={18} />, label: 'Espace Famille', href: '/dashboard/parent', permissions: [Permissions.ParentDashboardView] },
                { icon: <FiMail size={18} />, label: t.common.messages, href: '/dashboard/messages', permissions: [Permissions.MessagesView] },
            ]
        },
        {
            title: 'Pédagogie',
            module: 'scolarite',
            items: [
                { icon: <FiTarget size={18} />, label: 'Missions & Révisions', href: '/dashboard/missions' },
                { icon: <FiCheckSquare size={18} />, label: 'Corrections Audio', href: '/dashboard/missions/review', permissions: [Permissions.HomeworkManage] },
                { icon: <FiCheckSquare size={18} />, label: 'Évaluations', href: '/dashboard/evaluations', permissions: [Permissions.ExamsView] },
                { icon: <FiCalendar size={18} />, label: (t.common as any).sessions || 'Séances', href: '/dashboard/sessions', permissions: [Permissions.SessionsView] },
                { icon: <FiBookOpen size={18} />, label: (t.common as any).mushaf || 'Mushaf', href: '/dashboard/mushaf' },
                { icon: <FiBook size={18} />, label: t.common.exams, href: '/dashboard/exams', permissions: [Permissions.ExamsView] },
                { icon: <FiBookOpen size={18} />, label: t.common.homework, href: '/dashboard/homework' },
            ]
        },
        {
            title: 'Activités Mosquée',
            module: 'gestion',
            items: [
                { icon: <FiMessageCircle size={18} />, label: 'Communication', href: '/dashboard/mosque/communication' },
                { icon: <FiCalendar size={18} />, label: 'Événements', href: '/dashboard/mosque/events' },
                { icon: <FiUsers size={18} />, label: 'Bénévolat', href: '/dashboard/mosque/volunteering' },
                { icon: <FiDollarSign size={18} />, label: 'Dons & Collectes', href: '/dashboard/mosque/donations' },
                { icon: <FiCalendar size={18} />, label: 'Horaires de Prière', href: '/dashboard/mosque/prayer-times' },
                { icon: <FiBookOpen size={18} />, label: 'Pages du Site', href: '/dashboard/mosque/pages' },
                { icon: <FiShield size={18} />, label: 'Service Funéraire', href: '/dashboard/mosque/funeral' },
                { icon: <FiMapPin size={18} />, label: 'Cimetière', href: '/dashboard/mosque/cemetery' },
            ]
        },
        {
            title: 'Organisation',
            module: 'scolarite',
            items: [
                { icon: <FiGrid size={18} />, label: t.common.groups, href: '/dashboard/groups', permissions: [Permissions.GroupsView] },
