}

'use client';

import React, { useEffect, useState, useRef } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { useLiveSessionStore } from '@/lib/store/useLiveSessionStore';
import { FiArrowLeft, FiUsers, FiVideo, FiMic, FiMicOff, FiVideoOff, FiSettings, FiMaximize, FiMinimize, FiBookOpen } from 'react-icons/fi';
import CockpitSidebar from '@/components/sessions/CockpitSidebar';
import CockpitMushaf from '@/components/sessions/CockpitMushaf';
import * as signalR from '@microsoft/signalr';
import { useAuthStore } from '@/lib/store';
import { UserRole } from '@/types';

declare global {
    interface Window {
        JitsiMeetExternalAPI: any;
    }
}


export default function VirtualClassroomClient() {
    const { id } = useParams();
    const router = useRouter();
    const { user } = useAuthStore();
    const { cockpit, fetchCockpit, isLoading, error, activeStudentId, setHubConnection, updateMushafStateLocally } = useLiveSessionStore();
    const isTeacher = user?.roles.includes(UserRole.Teacher) || user?.roles.includes(UserRole.Admin);

    const [jitsiApi, setJitsiApi] = useState<any>(null);
    const jitsiContainerRef = useRef<HTMLDivElement>(null);
    const [sidebarOpen, setSidebarOpen] = useState(true);

    // Responsive State
    const [isMobile, setIsMobile] = useState(false);
    const [isLandscape, setIsLandscape] = useState(false);
    const [activeTab, setActiveTab] = useState<'mushaf' | 'queue' | 'chat'>('mushaf');

    useEffect(() => {
        const handleResize = () => {
            const mobile = window.innerWidth < 1024;
            setIsMobile(mobile);
            setIsLandscape(window.innerWidth > window.innerHeight && mobile);

            // Auto-close sidebar on mobile/landscape to give space to video
            if (mobile) setSidebarOpen(false);
            else setSidebarOpen(true);
        };
        handleResize();
        window.addEventListener('resize', handleResize);
        return () => window.removeEventListener('resize', handleResize);
    }, []);

    // SignalR Connection
    useEffect(() => {
        if (!id || !user) return;

        const API_URL = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5000';
        const connection = new signalR.HubConnectionBuilder()
            .withUrl(`${API_URL}/notificationHub`, {
                accessTokenFactory: () => user.token || '',
                skipNegotiation: true,
                transport: signalR.HttpTransportType.WebSockets
            })
            .withAutomaticReconnect()
            .build();

        connection.on('MushafStateUpdated', (state) => {
            console.log('Mushaf state synced:', state);
            updateMushafStateLocally(state);
        });

        const startConnection = async () => {
            try {
                await connection.start();
                await connection.invoke('JoinSessionGroup', id);
                setHubConnection(connection);
                console.log('Session SignalR Connected');
            } catch (err) {
                console.error('SignalR Session Error', err);
            }
        };

        startConnection();

        return () => {
            connection.stop();
            setHubConnection(null);
        };
    }, [id, user, setHubConnection, updateMushafStateLocally]);

    useEffect(() => {
        if (id) {
            fetchCockpit(id as string);
        }
    }, [id, fetchCockpit]);

    // Load Jitsi script
    useEffect(() => {
        const script = document.createElement('script');
        script.src = 'https://meet.jit.si/external_api.js';
        script.async = true;
        script.onload = () => initJitsi();
        document.body.appendChild(script);

        return () => {
            if (script.parentNode) {
                document.body.removeChild(script);
            }
            if (jitsiApi) {
                jitsiApi.dispose();
            }
        };
    }, [cockpit]);

    const initJitsi = () => {
        if (!cockpit || !jitsiContainerRef.current || window.JitsiMeetExternalAPI === undefined) return;

        const roomName = cockpit.meetingUrl
            ? cockpit.meetingUrl.split('/').pop()
            : `QuranSchool-${id?.toString().substring(0, 8)}`;

        const options = {
            roomName: roomName,
            width: '100%',
            height: '100%',
            parentNode: jitsiContainerRef.current,
            configOverwrite: {
                startWithAudioMuted: false,
                disableDeepLinking: true,
                prejoinPageEnabled: false
            },
            interfaceConfigOverwrite: {
                TOOLBAR_BUTTONS: [
                    'microphone', 'camera', 'closedcaptions', 'desktop', 'fullscreen',
                    'fodeviceselection', 'hangup', 'profile', 'chat', 'recording',
                    'livestreaming', 'etherpad', 'sharedvideo', 'settings', 'raisehand',
                    'videoquality', 'filmstrip', 'invite', 'feedback', 'stats', 'shortcuts',
                    'tileview', 'videobackgroundblur', 'download', 'help', 'mute-everyone',
                    'security'
                ],
            },
            userInfo: {
                displayName: user?.fullName || 'Enseignant'
            }
        };

        const api = new window.JitsiMeetExternalAPI('meet.jit.si', options);
        setJitsiApi(api);
    };

    if (isLoading) {
        return (
            <div className="flex h-screen items-center justify-center bg-dark-950">
                <div className="text-center">
                    <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-500 mx-auto mb-4"></div>
                    <p className="text-dark-400">Préparation de la classe virtuelle...</p>
                </div>
            </div>
        );
    }

    if (error || !cockpit) {
        return (
            <div className="flex h-screen items-center justify-center bg-dark-950">
                <div className="bg-dark-900 p-8 rounded-2xl border border-red-900/30 text-center max-w-md">
                    <h2 className="text-lg font-bold text-white mb-2">Erreur</h2>
                    <p className="text-dark-400 mb-6">{error || "Séance introuvable."}</p>
                    <button onClick={() => router.push('/dashboard/sessions')} className="btn btn-primary w-full">Retour</button>
                </div>
            </div>
        );
    }

    // Render for Mobile Portrait
    if (isMobile && !isLandscape) {
        return (
            <div className="flex flex-col h-screen bg-black text-white font-sans overflow-hidden">
                {/* Status Bar Overlay */}
                <div className="bg-primary-950 px-4 py-3 flex items-center justify-between shrink-0 border-b border-white/5">
                    <button onClick={() => router.push(`/dashboard/sessions/${id}`)} className="size-8 rounded-full bg-white/5 flex items-center justify-center text-dark-400 hover:text-white transition-colors">
                        <FiArrowLeft size={16} />
                    </button>
                    <div className="flex items-center gap-2">
                        <div className="size-2 rounded-full bg-red-500 animate-pulse shadow-[0_0_8px_rgba(239,68,68,0.5)]" />
                        <span className="text-[10px] font-black uppercase tracking-[0.2em]">{cockpit.groupName}</span>
                    </div>
                    <div className="size-8 rounded-full bg-white/5 flex items-center justify-center text-accent-gold">
                        <FiVideo size={14} />
                    </div>
                </div>

                {/* Video Area (YouTube Style - Fixed Top) */}
                <div className="aspect-video bg-dark-950 relative shadow-2xl z-20">
                    <div ref={jitsiContainerRef} className="absolute inset-0" />
                    {/* Minimalist Overlay if loading */}
                    {!jitsiApi && (
                        <div className="flex items-center justify-center h-full bg-dark-900">
                             <div className="spinner-border animate-spin inline-block w-6 h-6 border-2 border-primary-500 rounded-full border-t-white" />
                        </div>
                    )}
                </div>

                {/* Interaction Tabs (Premium Styled) */}
                <div className="flex bg-dark-900 border-b border-white/5 shrink-0 px-2 overflow-x-auto no-scrollbar">
                    {[
                        { id: 'mushaf', label: 'Récitation', icon: <FiVideo className="text-sm" /> },
                        { id: 'queue', label: `File (${cockpit.smartQueue?.length || 0})`, icon: <FiUsers className="text-sm" /> },
                        { id: 'chat', label: 'Chat', icon: <FiSettings className="text-sm" /> }
                    ].map(tab => (
                        <button 
                            key={tab.id}
                            onClick={() => setActiveTab(tab.id as any)}
                            className={`flex items-center gap-2 px-6 py-4 text-[10px] font-black uppercase tracking-[0.2em] transition-all whitespace-nowrap relative ${activeTab === tab.id ? 'text-accent-gold' : 'text-dark-500'}`}
                        >
                            {tab.icon}
                            {tab.label}
                            {activeTab === tab.id && (
                                <div className="absolute bottom-0 left-0 right-0 h-1 bg-accent-gold rounded-full" />
                            )}
                        </button>
                    ))}
                </div>

                {/* Scrollable Feature Area */}
                <div className="flex-1 overflow-y-auto bg-dark-950/50 relative">
                    <div className="absolute inset-0 zellige-pattern opacity-5 pointer-events-none" />

                    <div className="relative z-10 h-full">
                        {activeTab === 'mushaf' && (
                            <div className="p-4 h-full animate-fade-in">
                                {activeStudentId ? (
                                    <div className="rounded-[2.5rem] bg-white dark:bg-dark-900 border border-dark-800 h-full overflow-hidden shadow-2xl">
                                        <CockpitMushaf />
                                    </div>
                                ) : (
                                    <div className="flex flex-col items-center justify-center h-full text-dark-500 text-center space-y-6">
                                        <div className="size-24 rounded-[2rem] bg-dark-900 border border-dark-800 flex items-center justify-center text-primary-500/20">
                                            <FiVideo size={48} />
                                        </div>
                                        <div className="space-y-2">
                                            <p className="text-sm font-bold text-white uppercase tracking-widest">En attente de récitation</p>
                                            <p className="text-[10px] uppercase font-medium max-w-xs opacity-40">Sélectionnez un élève dans la file pour suivre sa lecture en direct.</p>
                                        </div>
                                    </div>
                                )}
                            </div>
                        )}
                        {activeTab === 'queue' && (
                            <div className="h-full animate-slide-in-up">
                                <CockpitSidebar />
                            </div>
                        )}
                        {activeTab === 'chat' && (
                            <div className="flex flex-col items-center justify-center h-full p-10 text-center space-y-6 bg-dark-900/50">
                                <div className="size-20 rounded-full bg-primary-950/50 flex items-center justify-center text-accent-gold">
                                    <FiSettings size={32} />
                                </div>
                                <h3 className="text-lg font-black tracking-tight text-white cinzel-title uppercase">Communication</h3>
                                <p className="text-xs text-dark-400 font-medium leading-relaxed">
                                    Les outils de communication directe sont intégrés à l&apos;interface vidéo en haut de l&apos;écran ou via les profils élèves dans la file.
                                </p>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        );
    }

    // Render for Mobile Landscape (Immersive / Optimized Split)
    if (isLandscape) {
        return (
            <div className="flex h-screen bg-black text-white font-sans overflow-hidden">
                {/* Horizontal Tool Bar (Left) */}
                <div className="w-16 bg-primary-950 flex flex-col items-center py-6 gap-6 border-r border-white/5 shrink-0">
                    <button onClick={() => router.push(`/dashboard/sessions/${id}`)} className="size-10 rounded-2xl bg-white/5 flex items-center justify-center text-dark-400 hover:text-white transition-all">
                        <FiArrowLeft size={18} />
                    </button>
                    <div className="h-px w-6 bg-white/10" />
                    <button 
                        onClick={() => setActiveTab('mushaf')}
                        className={`size-12 rounded-2xl flex items-center justify-center transition-all ${activeTab === 'mushaf' ? 'bg-primary-600 text-white shadow-lg' : 'text-dark-400 hover:bg-white/5'}`}
                        title="Mushaf"
                    >
                        <FiVideo size={20} />
                    </button>
                    <button 
                        onClick={() => setActiveTab('queue')}
                        className={`size-12 rounded-2xl flex items-center justify-center transition-all ${activeTab === 'queue' ? 'bg-primary-600 text-white shadow-lg' : 'text-dark-400 hover:bg-white/5'}`}
                        title="File"
                    >
                        <FiUsers size={20} />
                    </button>
                    <div className="mt-auto">
                        <button 
                            onClick={() => setSidebarOpen(!sidebarOpen)}
                            className={`size-12 rounded-2xl flex items-center justify-center transition-all ${sidebarOpen ? 'bg-accent-gold text-primary-950' : 'text-dark-400 hover:bg-white/5'}`}
                        >
                            {sidebarOpen ? <FiMinimize size={20} /> : <FiMaximize size={20} />}
                        </button>
                    </div>
                </div>

                {/* Large Video Area */}
                <div className={`relative flex-grow bg-dark-950 transition-all duration-500 overflow-hidden ${sidebarOpen ? 'flex-[1.5]' : 'flex-[3]'}`}>
                    <div ref={jitsiContainerRef} className="absolute inset-0" />

                    {/* Immersive Tag */}
                    {!sidebarOpen && (
                        <div className="absolute bottom-6 left-6 pointer-events-none opacity-50">
                            <div className="flex items-center gap-2 bg-black/40 backdrop-blur-xl px-4 py-2 rounded-full border border-white/10">
                                <span className="size-1.5 rounded-full bg-accent-gold animate-pulse" />
                                <span className="text-[9px] font-black uppercase tracking-widest">{cockpit.groupName}</span>
                            </div>
                        </div>
                    )}
                </div>

                {/* Side Split Contextual Tool */}
                {sidebarOpen && (
                    <div className="flex-1 bg-dark-900 border-l border-white/10 shadow-2xl relative animate-slide-in-right">
                        <div className="absolute inset-0 zellige-pattern opacity-5 pointer-events-none" />
                        <div className="h-full flex flex-col relative z-10">
                            <div className="p-4 bg-dark-950/80 border-b border-white/5 flex items-center justify-between">
                                <h3 className="text-[10px] font-black uppercase tracking-[0.3em] text-accent-gold">
                                    {activeTab === 'mushaf' ? 'Suivi Récitation' : 'File d\'attente'}
                                </h3>
                                <button onClick={() => setSidebarOpen(false)} className="text-dark-500 hover:text-white">
                                    <FiMinimize size={14} />
                                </button>
                            </div>
                            <div className="flex-1 overflow-y-auto no-scrollbar">
                                {activeTab === 'mushaf' ? (
                                    activeStudentId ? <CockpitMushaf /> : (
                                        <div className="h-full flex flex-col items-center justify-center p-10 opacity-30">
                                            <FiVideo size={40} className="mb-4" />
                                            <p className="text-[10px] font-bold uppercase tracking-widest text-center">Sélectionnez un élève</p>
                                        </div>
                                    )
                                ) : <CockpitSidebar />}
                            </div>
                        </div>
                    </div>
                )}
            </div>
        );
    }

    // Default Desktop Render (Fine-tuned for High-End Dashboard)
    return (
        <div className="flex bg-[#0A0B0E] h-screen overflow-hidden text-white font-sans">
            {/* Control Column (Left) */}
            <div className="w-20 bg-primary-950 flex flex-col items-center py-8 gap-10 border-r border-white/5 shrink-0">
                <button onClick={() => router.push(`/dashboard/sessions/${id}`)} className="size-12 rounded-2xl bg-white/5 flex items-center justify-center text-dark-400 hover:text-white hover:bg-accent-gold/20 transition-all group">
                    <FiArrowLeft size={24} className="group-hover:-translate-x-1 transition-transform" />
                </button>
                <div className="h-[2px] w-8 bg-white/5" />
                <button className="size-14 rounded-2xl bg-accent-gold text-primary-950 shadow-[0_15px_30px_rgba(234,179,8,0.3)] flex items-center justify-center">
                    <FiVideo size={28} />
                </button>
                <button className="size-14 rounded-2xl text-white/40 hover:text-white hover:bg-white/5 transition-all flex items-center justify-center">
                    <FiSettings size={28} />
                </button>
                <div className="mt-auto pb-4">
                    <div className="size-12 rounded-full border-2 border-primary-800 p-0.5">
                        <div className="size-full rounded-full bg-accent-gold flex items-center justify-center text-primary-950 font-black text-xs">
                            {user?.fullName?.charAt(0) || 'E'}
                        </div>
                    </div>
                </div>
            </div>

            {/* Main Interactive Workspace */}
            <div className="flex-1 flex flex-col overflow-hidden relative">
                {/* Visual Motif */}
                <div className="absolute top-0 right-0 w-[600px] h-[600px] bg-primary-900/10 rounded-full blur-[120px] -z-10" />

                <header className="h-20 bg-dark-950/40 backdrop-blur-2xl border-b border-white/5 flex items-center justify-between px-10 shrink-0 relative z-20">
                    <div className="flex items-center gap-6">
                        <div className="flex items-center gap-4">
                            <div className="size-3 bg-red-600 rounded-full animate-ping opacity-75" />
                            <h1 className="text-xl font-serif font-black tracking-tighter cinzel-title uppercase">
                                Session In Live <span className="text-accent-gold mx-2">/</span> {cockpit.groupName}
                            </h1>
                        </div>
                    </div>

                    <div className="flex items-center gap-4">
                        <div className="px-4 py-2 bg-white/5 border border-white/10 rounded-xl flex items-center gap-3">
                            <div className="flex -space-x-2">
                                {[1,2,3].map(i => (
                                    <div key={i} className="size-6 rounded-full bg-dark-800 border-2 border-primary-950" />
                                ))}
                            </div>
                            <span className="text-[10px] font-black tracking-widest text-white/60 uppercase">
                                {cockpit.smartQueue?.length || 0} Élèves Connectés
                            </span>
                        </div>
                        <button
                            onClick={() => setSidebarOpen(!sidebarOpen)}
                            className={`size-12 rounded-xl transition-all flex items-center justify-center border ${sidebarOpen ? 'bg-primary-900 border-primary-700 text-white' : 'bg-white/5 border-white/10 text-dark-400 hover:text-white'}`}
                        >
                            <FiUsers size={20} />
                        </button>
                    </div>
                </header>

                <div className="flex-1 flex overflow-hidden">
                    {/* Primary Split: Video & Tracking */}
                    <div className={`flex-[1.2] min-w-0 relative border-r border-white/5 transition-all duration-700 ${sidebarOpen ? 'm-8 mr-4' : 'm-0'}`}>
                        <div className={`size-full bg-black relative overflow-hidden ${sidebarOpen ? 'rounded-[3rem] shadow-[0_50px_100px_rgba(0,0,0,0.5)] border border-white/5' : ''}`}>
                             <div ref={jitsiContainerRef} className="absolute inset-0" />
                        </div>
                    </div>

                    {/* Secondary Split: Quran / Follow-up */}
                    <div className={`flex-1 overflow-y-auto no-scrollbar transition-all duration-700 ${sidebarOpen ? 'm-8 ml-4 mr-0' : 'm-0'} bg-dark-900/20 backdrop-blur-md rounded-[3rem] border border-white/5 overflow-hidden`}>
                        {activeStudentId ? (
                             <div className="h-full animate-fade-in">
                                <CockpitMushaf />
                             </div>
                        ) : (
                            <div className="flex flex-col items-center justify-center h-full p-20 text-center space-y-8">
                                <div className="size-32 rounded-[2.5rem] bg-primary-950/40 border border-white/5 flex items-center justify-center text-primary-500/20">
                                    <FiBookOpen size={64} />
                                </div>
                                <div className="space-y-4">
                                    <h3 className="text-3xl font-serif font-black cinzel-title uppercase tracking-tighter">Prêt pour la récitation</h3>
                                    <p className="text-sm font-medium text-white/40 max-w-sm mx-auto leading-relaxed">
                                        Sélectionnez un étudiant dans la file d&apos;attente active pour synchroniser son Mushaf et commencer le suivi personnalisé.
                                    </p>
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            </div>

            {/* Smart Sidebar - Right */}
            <aside className={`
                ${sidebarOpen ? 'w-[420px]' : 'w-0'} 
                transition-all duration-500 ease-in-out border-l border-white/5 bg-primary-950/30 backdrop-blur-3xl flex flex-col h-full z-30 shrink-0 overflow-hidden relative
            `}>
                <div className="w-[420px] flex flex-col h-full relative z-10">
                    <div className="absolute inset-0 zellige-pattern opacity-5" />
                    <div className="p-8 border-b border-white/5 flex items-center justify-between relative bg-black/20">
                        <div>
                            <h2 className="text-[11px] font-black tracking-[0.4em] text-accent-gold uppercase mb-1">Queue Management</h2>
                            <p className="text-[10px] font-medium text-white/30 uppercase tracking-[0.2em]">Priorité Optimisée / API-Q</p>
                        </div>
                    </div>

                    <div className="flex-1 overflow-y-auto no-scrollbar relative">
                        <CockpitSidebar />
                    </div>
                </div>
            </aside>
        </div>
    );
}

'use client';
import PageSkeleton from '@/components/ui/PageSkeleton';

import { useEffect, useState } from 'react';
import { useAuthStore, useUIStore } from '@/lib/store';
import { useTranslation } from '@/lib/i18n/translations';
import api, { dashboardApi, sessionApi, reportApi } from '@/lib/api/client';
import { missionsService } from '@/lib/services/missions';
import { StudentMissionResponse } from '@/types';
import { format } from 'date-fns';
import { fr } from 'date-fns/locale';
import { FaBook, FaClipboardList, FaCalendarAlt, FaMicrophone, FaTimes } from 'react-icons/fa';
import { FiVideo, FiDownload } from 'react-icons/fi';
import Link from 'next/link';
import MissionRecordingCard from '@/components/missions/MissionRecordingCard';

interface StudentDashboardData {
    studentName: string;
    groupName: string;
    attendanceRate: number;
    points: number;
    schedule: any[];
    pendingHomeworks: any[];
    upcomingExams: any[];
    studentProgress: {
        juzCompleted: number;
        surahsMemorized: number;
        currentJuz: number;
        lastSurah: string;
    };
}

export default function StudentDashboard() {
    const { user } = useAuthStore();
    const { locale } = useUIStore();
    const { t } = useTranslation(locale);
    const [data, setData] = useState<StudentDashboardData | null>(null);
    const [missions, setMissions] = useState<StudentMissionResponse[]>([]);
    const [selectedMission, setSelectedMission] = useState<StudentMissionResponse | null>(null);
    const [loading, setLoading] = useState(true);
    const [showRecordModal, setShowRecordModal] = useState(false);

    const [todaySessions, setTodaySessions] = useState<any[]>([]);

    useEffect(() => {
        if (!user?.userId) return;
        fetchDashboard();
        fetchTodaySessions();
        fetchMissions();
    }, [user?.userId]);

    const fetchMissions = async () => {
        try {
            const res = await missionsService.getStudentMissions(user!.userId);
            setMissions(res.filter(m => m.status === 'Pending' || m.status === 'Overdue'));
        } catch (e) {
            console.error('Failed to fetch missions', e);
        }
    };

    const fetchTodaySessions = async () => {
        try {
            const res = await sessionApi.getAll();
            const todayStr = format(new Date(), 'yyyy-MM-dd');
            const filtered = res.data.filter((s: any) =>
                s.date.split('T')[0] === todayStr &&
                s.isOnline &&
                (s.status === 'InProgress' || s.status === 'Planned')
            );
            setTodaySessions(filtered);
        } catch (e) {
            console.error('Failed to fetch today sessions', e);
        }
    };

    const fetchDashboard = async () => {
        try {
            setLoading(true);
            // using the centralized api instance ensures correct baseURL/api and headers
            // The backend expects the Student ID, not the User ID.
            // We ensure we use the studentId if available in the user object.
            const studentId = user?.studentId || user?.userId;
            const response = await api.get(`/api/dashboard/student/${studentId}`);
            setData(response.data);
        } catch (error) {
            console.error('Failed to fetch dashboard', error);
        } finally {
            setLoading(false);
        }
    };

    const handleRecordClick = (mission: StudentMissionResponse) => {
        setSelectedMission(mission);
        setShowRecordModal(true);
    };

    const handleDownloadPdf = async () => {
        if (!user?.userId) return;
        try {
            const { data } = await reportApi.downloadStudentPdf(user.userId);
            const url = window.URL.createObjectURL(new Blob([data]));
            const link = document.createElement('a');
            link.href = url;
            link.setAttribute('download', `Rapport_Progression.pdf`);
            document.body.appendChild(link);
            link.click();
            link.remove();
        } catch (error) {
            console.error('Failed to download PDF', error);
        }
    };

    if (!data) return <div className="text-center py-12 text-dark-400">{t.homework.noRecords}</div>;

    const dateLocale = locale === 'fr' ? fr : undefined;

    if (loading) return <PageSkeleton variant="dashboard" />;

    return (
        <div className="space-y-8 animate-fade-in font-sans">
            {/* Recording Modal */}
            {showRecordModal && selectedMission && (
                <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
                    <div className="absolute inset-0 bg-dark-950/60 backdrop-blur-sm" onClick={() => setShowRecordModal(false)}></div>
                    <div className="relative w-full max-w-lg animate-in zoom-in-95 duration-200">
                        <button
                            onClick={() => setShowRecordModal(false)}
                            className="absolute -top-12 right-0 text-white hover:text-dark-200 transition-colors"
                        >
                            <FaTimes size={24} />
                        </button>
                        <MissionRecordingCard
                            mission={selectedMission}
                            onSuccess={() => {
                                setShowRecordModal(false);
                                fetchMissions();
                            }}
                        />
                    </div>
                </div>
            )}
            <div className="bg-white dark:bg-dark-900 rounded-4xl p-8 border border-dark-100 dark:border-dark-800 shadow-sm relative overflow-hidden flex flex-col md:flex-row justify-between items-start md:items-center gap-6 group">
                <div className="absolute top-0 right-0 w-64 h-64 bg-primary-500/10 rounded-full -mr-20 -mt-20 blur-3xl group-hover:scale-110 transition-transform"></div>
                <div className="relative z-10">
                    <h1 className="text-3xl font-extrabold text-dark-900 dark:text-white tracking-tight">{t.common.welcome}, <span className="text-primary-600 dark:text-primary-400">{data.studentName}</span></h1>
                    <div className="flex items-center gap-3 mt-2">
                        <span className="px-3 py-1 bg-dark-50 dark:bg-dark-800 text-dark-600 dark:text-dark-300 text-xs font-bold rounded-lg border border-dark-200 dark:border-dark-700 tracking-wider uppercase">
                            {data.groupName}
                        </span>
                        <button
                            onClick={handleDownloadPdf}
                            className="flex items-center gap-2 px-3 py-1 bg-primary-100 dark:bg-primary-900/30 text-primary-600 dark:text-primary-400 text-[10px] font-black uppercase tracking-widest rounded-lg border border-primary-200 dark:border-primary-800/50 hover:bg-primary-200 transition-colors"
                        >
                            <FiDownload className="w-3 h-3" />
                            Mon Bulletin PDF
                        </button>
                    </div>
                </div>
                <div className="flex flex-col md:flex-row items-start md:items-center gap-4 relative z-10">
                    <div className="text-left md:text-right bg-dark-50 dark:bg-dark-800/50 p-4 rounded-3xl border border-dark-100 dark:border-dark-700/50 min-w-[120px]">
                        <p className="text-xs text-dark-500 font-bold uppercase tracking-wider mb-1">Ma Série</p>
                        <p className="text-3xl font-black tracking-tight text-orange-500 flex items-center justify-end gap-2">
                            {data.points > 0 ? '🔥' : '❄️'} {data.points > 100 ? (data.points / 100).toFixed(0) : 0} j
                        </p>
                    </div>
                    <div className="text-left md:text-right bg-dark-50 dark:bg-dark-800/50 p-4 rounded-3xl border border-dark-100 dark:border-dark-700/50 min-w-[120px]">
                        <p className="text-xs text-dark-500 font-bold uppercase tracking-wider mb-1">Total XP</p>
                        <p className="text-3xl font-black tracking-tight text-primary-600 dark:text-primary-400">
                            {data.points}
                        </p>
                    </div>
                </div>
            </div>

            {/* Active Online Session Banner */}
            {todaySessions.filter(s => s.status === 'InProgress').map(s => (
                <div key={s.id} className="bg-primary-600 rounded-4xl p-8 text-white shadow-xl shadow-primary-500/20 flex flex-col md:flex-row items-center justify-between gap-6 border border-primary-400/30 overflow-hidden relative group transition-all hover:shadow-2xl">
                    <div className="absolute top-0 right-0 w-64 h-64 bg-white/10 rounded-full -mr-20 -mt-20 blur-3xl"></div>
                    <div className="flex items-center gap-6 relative z-10">
                        <div className="w-20 h-20 rounded-3xl bg-white/20 flex items-center justify-center text-4xl shadow-inner border border-white/20">
                            <FiVideo />
                        </div>
                        <div>
                            <div className="flex items-center gap-2 mb-1">
                                <span className="w-2 h-2 rounded-full bg-red-400 animate-pulse"></span>
                                <h2 className="text-xl font-black uppercase tracking-wider">Ma séance en direct</h2>
                            </div>
                            <p className="text-primary-100 font-bold text-lg">{s.startTime} : {s.sessionObjective || 'Récitation du jour'}</p>
                        </div>
                    </div>
                    <Link href={`/dashboard/sessions/${s.id}/live`} className="btn bg-white text-primary-600 hover:bg-blue-50 px-10 py-4 rounded-2xl font-black shadow-lg shadow-black/10 transition-all hover:scale-105 active:scale-95 relative z-10 whitespace-nowrap text-lg">
                        Rejoindre la classe
                    </Link>
                </div>
            ))}

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                {/* Progress */}
                <div className="bg-white dark:bg-dark-900 rounded-4xl p-8 border border-dark-100 dark:border-dark-800 shadow-sm relative overflow-hidden group">
                    <div className="absolute top-0 right-0 w-32 h-32 bg-primary-500/10 rounded-full -mr-16 -mt-16 blur-2xl group-hover:scale-110 transition-transform"></div>
                    <h3 className="text-xl font-bold text-dark-900 dark:text-white mb-6 flex items-center gap-3 relative z-10">
                        <div className="w-10 h-10 rounded-xl bg-primary-100 dark:bg-primary-900/30 flex items-center justify-center text-primary-600">
                            <FaBook className="w-5 h-5" />
                        </div>
                        {t.progress.myProgress}
                    </h3>
                    <div className="space-y-4 relative z-10">
                        <div className="flex justify-between items-center bg-dark-50 dark:bg-dark-800/50 p-4 rounded-2xl border border-transparent hover:border-dark-200 dark:hover:border-dark-700 transition-colors">
                            <span className="text-dark-600 dark:text-dark-300 font-medium">{t.progress.juzCompleted}</span>
                            <span className="font-extrabold text-lg text-dark-900 dark:text-white">{data.studentProgress.juzCompleted}</span>
                        </div>
                        <div className="flex justify-between items-center bg-dark-50 dark:bg-dark-800/50 p-4 rounded-2xl border border-transparent hover:border-dark-200 dark:hover:border-dark-700 transition-colors">
                            <span className="text-dark-600 dark:text-dark-300 font-medium">{t.progress.surahsMemorized}</span>
                            <span className="font-extrabold text-lg text-dark-900 dark:text-white">{data.studentProgress.surahsMemorized}</span>
                        </div>
                        <div className="flex justify-between items-center bg-dark-50 dark:bg-dark-800/50 p-4 rounded-2xl border border-transparent hover:border-dark-200 dark:hover:border-dark-700 transition-colors">
                            <span className="text-dark-600 dark:text-dark-300 font-medium">{t.progress.currentJuz}</span>
                            <span className="font-extrabold text-lg text-primary-600 dark:text-primary-400">{data.studentProgress.currentJuz || '-'}</span>
                        </div>
                        <div className="flex justify-between items-center bg-dark-50 dark:bg-dark-800/50 p-4 rounded-2xl border border-transparent hover:border-dark-200 dark:hover:border-dark-700 transition-colors">
                            <span className="text-dark-600 dark:text-dark-300 font-medium">{t.progress.lastSurah}</span>
                            <span className="font-bold text-dark-900 dark:text-white truncate max-w-[120px]">{data.studentProgress.lastSurah}</span>
                        </div>
                    </div>
                </div>

                {/* Pending Homework */}
                <div className="bg-white dark:bg-dark-900 rounded-4xl p-8 border border-dark-100 dark:border-dark-800 shadow-sm relative overflow-hidden group flex flex-col">
                    <div className="absolute top-0 right-0 w-32 h-32 bg-orange-500/10 rounded-full -mr-16 -mt-16 blur-2xl group-hover:scale-110 transition-transform"></div>
                    <h3 className="text-xl font-bold text-dark-900 dark:text-white mb-6 flex items-center gap-3 relative z-10">
                        <div className="w-10 h-10 rounded-xl bg-orange-100 dark:bg-orange-900/30 flex items-center justify-center text-orange-600">
                            <FaClipboardList className="w-5 h-5" />
                        </div>
                        {t.common.homework}
                    </h3>
                    <div className="space-y-4 relative z-10 flex-1">
                        {data.pendingHomeworks.length === 0 ? (
                            <div className="text-center py-10 bg-dark-50 dark:bg-dark-800/50 rounded-3xl border border-dashed border-dark-200 dark:border-dark-700">
                                <p className="text-dark-500 font-bold">{t.homework.noHomework}</p>
                            </div>
                        ) : (
                            data.pendingHomeworks.slice(0, 3).map((hw: any) => (
                                <div key={hw.assignmentId} className="flex flex-col gap-2 bg-dark-50 dark:bg-dark-800/50 p-4 rounded-3xl hover:bg-dark-100 dark:hover:bg-dark-800 transition-colors border border-transparent hover:border-dark-200 dark:hover:border-dark-700">
                                    <div className="flex justify-between items-start">
                                        <p className="font-bold text-dark-900 dark:text-white text-base leading-tight pr-4">{hw.title}</p>
                                        <Link
                                            href={`/dashboard/homework/${hw.assignmentId}`}
                                            className="text-primary-600 dark:text-primary-400 text-[10px] font-extrabold uppercase tracking-widest bg-primary-50 dark:bg-primary-900/20 px-3 py-1.5 rounded-xl hover:bg-primary-100 dark:hover:bg-primary-900/40 transition-colors whitespace-nowrap"
                                        >
                                            {t.homework.doIt}
                                        </Link>
                                    </div>
                                    <p className="text-xs text-orange-600 dark:text-orange-400 font-bold">
                                        {t.homework.due}: {format(new Date(hw.dueDate), 'd MMM', { locale: dateLocale })}
                                    </p>
                                </div>
                            ))
                        )}
                    </div>
                    {data.pendingHomeworks.length > 0 && (
                        <div className="mt-6 text-center relative z-10 pt-4 border-t border-dark-100 dark:border-dark-800">
                            <Link href="/dashboard/homework" className="text-primary-600 dark:text-primary-400 text-sm font-bold hover:text-primary-700 dark:hover:text-primary-300 transition-colors">
                                {t.homework.viewAll} →
                            </Link>
                        </div>
                    )}
                </div>

                {/* Upcoming Exams */}
                <div className="bg-white dark:bg-dark-900 rounded-4xl p-8 border border-dark-100 dark:border-dark-800 shadow-sm relative overflow-hidden group">
                    <div className="absolute top-0 right-0 w-32 h-32 bg-purple-500/10 rounded-full -mr-16 -mt-16 blur-2xl group-hover:scale-110 transition-transform"></div>
                    <h3 className="text-xl font-bold text-dark-900 dark:text-white mb-6 flex items-center gap-3 relative z-10">
                        <div className="w-10 h-10 rounded-xl bg-purple-100 dark:bg-purple-900/30 flex items-center justify-center text-purple-600">
                            <FaCalendarAlt className="w-5 h-5" />
                        </div>
                        {t.homework.upcomingExams}
                    </h3>
                    <div className="space-y-4 relative z-10">
                        {data.upcomingExams.length === 0 ? (
                            <div className="text-center py-10 bg-dark-50 dark:bg-dark-800/50 rounded-3xl border border-dashed border-dark-200 dark:border-dark-700">
                                <p className="text-dark-500 font-bold">{t.homework.noExams}</p>
                            </div>
                        ) : (
                            data.upcomingExams.map((e: any) => (
                                <div key={e.examId} className="flex justify-between items-center bg-purple-50/50 dark:bg-purple-900/10 p-4 rounded-3xl border border-purple-100 dark:border-purple-800/50 hover:bg-purple-50 dark:hover:bg-purple-900/20 transition-colors">
                                    <p className="font-bold text-dark-900 dark:text-white text-base">{e.title}</p>
                                    <span className="text-xs text-purple-600 dark:text-purple-400 font-extrabold bg-purple-100 dark:bg-purple-900/40 px-3 py-1.5 rounded-lg">
                                        {format(new Date(e.examDate), 'd MMM', { locale: dateLocale })}
                                    </span>
                                </div>
                            ))
                        )}
                    </div>
                </div>

                {/* Missions Card */}
                <div className="bg-white dark:bg-dark-900 rounded-4xl p-8 border border-dark-100 dark:border-dark-800 shadow-sm relative overflow-hidden group col-span-1 md:col-span-2 lg:col-span-3">
                    <div className="absolute top-0 right-0 w-64 h-64 bg-emerald-500/5 rounded-full -mr-20 -mt-20 blur-3xl"></div>
                    <div className="flex justify-between items-center mb-6 relative z-10">
                        <h3 className="text-xl font-bold text-dark-900 dark:text-white flex items-center gap-3">
                            <div className="w-10 h-10 rounded-xl bg-emerald-100 dark:bg-emerald-900/30 flex items-center justify-center text-emerald-600">
                                <FaMicrophone className="w-5 h-5" />
                            </div>
                            Missions de Récitation
                        </h3>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 relative z-10">
                        {missions.length === 0 ? (
                            <div className="col-span-full text-center py-12 bg-dark-50 dark:bg-dark-900/30 rounded-3xl border border-dashed border-dark-200 dark:border-dark-700">
                                <p className="text-dark-500 font-bold uppercase tracking-widest text-xs">Toutes les missions sont complétées !</p>
                            </div>
                        ) : (
                            missions.map((m) => (
                                <div key={m.id} className="bg-white dark:bg-dark-800 border border-dark-100 dark:border-dark-700 p-5 rounded-3xl flex flex-col justify-between hover:border-emerald-200 dark:hover:border-emerald-900 transition-all group">
                                    <div>
                                        <div className="flex justify-between items-start mb-2">
                                            <span className={`px-2 py-0.5 rounded-md text-[10px] font-black uppercase tracking-wider ${m.type === 'SmartRevision' ? 'bg-purple-100 text-purple-600' : 'bg-primary-100 text-primary-600'
                                                }`}>
                                                {m.type === 'SmartRevision' ? 'Révision' : 'Devoir'}
                                            </span>
                                            <span className="text-[10px] text-dark-400 font-bold">{format(new Date(m.dueDate), 'd MMM', { locale: dateLocale })}</span>
                                        </div>
                                        <p className="font-extrabold text-lg text-dark-900 dark:text-white leading-tight mb-1">
                                            {m.targetType === 'Surah' ? `Sourate ${m.targetId}` : m.customDescription}
                                        </p>
                                        <p className="text-xs text-dark-500 font-medium">Assigné par {m.teacherName || 'Système'}</p>
                                    </div>
                                    <button
                                        onClick={() => handleRecordClick(m)}
                                        className="mt-4 w-full py-3 bg-emerald-600 hover:bg-emerald-700 text-white rounded-2xl font-black text-sm flex items-center justify-center gap-2 transition-all shadow-md shadow-emerald-600/20 group-hover:scale-[1.02]"
                                    >
                                        <FaMicrophone /> Réciter maintenant
                                    </button>
                                </div>
                            ))
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
}

'use client';
import PageSkeleton from '@/components/ui/PageSkeleton';

import { useEffect, useState, useMemo } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { useUIStore } from '@/lib/store';
import { useTranslation } from '@/lib/i18n/translations';
import { studentApi, groupApi } from '@/lib/api/client';
import { StudentResponse, GroupResponse, ExamResponse, SessionResponse, HomeworkAssignmentResponse } from '@/types';
import {
    FiArrowLeft, FiEdit2, FiTrash2, FiUser, FiMail, FiPhone,
    FiCalendar, FiHash, FiTarget, FiActivity,
    FiBookOpen, FiPlus, FiChevronRight, FiCheckCircle, FiClock as FiClockIcon,
    FiXCircle, FiAlertCircle
} from 'react-icons/fi';
import Link from 'next/link';

// ═══════════════════════════════════════════════════════════════════════════════
// MOCK DATA (if API fails)
// ═══════════════════════════════════════════════════════════════════════════════
